function buildLangCountryAvailabilityMap(items = []) {
  const map = new Map();
  for (const item of Array.isArray(items) ? items : []) {
    const langKey = normalizeSongLanguage(item?.lang || "");
    const countryKey = normalizeSongCountry(item?.country || "");
    const count = Number(item?.count || 0);
    if (!langKey || !countryKey || count <= 0) continue;
    if (!map.has(langKey)) map.set(langKey, new Set());
    map.get(langKey).add(countryKey);
  }
  return map;
}

function buildLangCountryPeriodAvailabilityMap(items = []) {
  const map = new Map();
  for (const item of Array.isArray(items) ? items : []) {
    const langKey = normalizeSongLanguage(item?.lang || "");
    const countryKey = normalizeSongCountry(item?.country || "");
    const periodKey = normalizeSongPeriod(item?.period || "");
    const count = Number(item?.count || 0);
    if (!langKey || !countryKey || !periodKey || count <= 0) continue;
    const key = `${langKey}::${countryKey}`;
    if (!map.has(key)) map.set(key, new Set());
    map.get(key).add(periodKey);
  }
  return map;
}

