function renderHistoricalCountryCard(item = {}) {
  const countryKey = String(item?.country || item?.key || "").trim();
  const historicalMeta = item?.historicalMeta || getHistoricalAffiliationMeta(countryKey);
  const previewSong = {
    id: String(item?.key || item?.href || item?.title || "").trim() || `hist_${Math.random().toString(36).slice(2, 8)}`,
    title: historicalCardTitle(String(item?.label || item?.title || "").trim(), item?.year || ""),
    snippet: "",
    lang: String(item?.lang || "").trim(),
    country: countryKey,
    year: String(item?.year || "").trim(),
    count: Number(item?.count || 0),
    verified: 0,
  };
  return renderHomeSongCard(previewSong, {
    href: String(item?.href || "#/").trim() || "#/",
    cardKind: "historical-country",
    extraClass: `home-picker-card home-country-card-historical${item?.isActive ? " is-active" : ""}`,
    backgroundsByCountry: item?.backgroundsByCountry instanceof Map ? item.backgroundsByCountry : new Map(),
    flagUrl: String(item?.flagBg || "").trim(),
    historicalMeta,
    inlineStyle: historicalCountryCardStyle(countryKey),
  }).replace("<a ", `<a data-home-preview-card="1" data-home-bg="${esc(String(item?.previewBg || "").trim())}" `);
}

function homePickerDetailLine(label = "", value = "") {
  const safeLabel = String(label || "").trim();
  const safeValue = String(value || "").trim();
  if (!safeValue) return "";
  return safeLabel ? `${safeLabel}: ${safeValue}` : safeValue;
}

function homePickerCountrySortOrder(countryKey = "") {
  const normalized = normalizeSongCountry(countryKey || "") || "";
  if (!normalized) return Number.MAX_SAFE_INTEGER - 1;
  if (normalized === "other_countries") return Number.MAX_SAFE_INTEGER;
  const meta = getHistoricalAffiliationMeta(normalized);
  const order = Number(meta?.sort_order);
  return Number.isFinite(order) ? order : Number.MAX_SAFE_INTEGER - 1;
}

function renderHomePickerPreviewCard(item = {}, options = {}) {
  const backgroundsByCountry = options.backgroundsByCountry instanceof Map ? options.backgroundsByCountry : new Map();
  const previewSong = {
    id: String(item?.key || item?.href || item?.title || "").trim() || `picker_${Math.random().toString(36).slice(2, 8)}`,
    title: String(item?.title || "").trim(),
    snippet: (Array.isArray(item?.previewLines) ? item.previewLines : [])
      .map((line) => String(line || "").trim())
      .filter(Boolean)
      .join("\n"),
    lang: String(item?.lang || "").trim(),
    country: String(item?.country || "").trim(),
    year: String(item?.year || "").trim(),
    verified: 0,
  };
  return renderHomeSongCard(previewSong, {
    href: String(item?.href || "#/").trim() || "#/",
    cardKind: "picker",
    extraClass: `home-picker-card${item?.isActive ? " is-active" : ""}`,
    backgroundsByCountry,
  }).replace("<a ", `<a data-home-preview-card="1" data-home-bg="${esc(String(item?.previewBg || "").trim())}" `);
}

function renderHomeCatalogCard(item = {}) {
  if (item?.layout === "historical-country") {
    return renderHistoricalCountryCard(item);
  }
  const extraClass = String(item?.extraClass || "").trim();
  const previewSong = {
    id: String(item?.key || item?.href || item?.title || "").trim() || `country_${Math.random().toString(36).slice(2, 8)}`,
    title: String(item?.label || item?.title || "").trim(),
    snippet: "",
    lang: "",
    country: String(item?.country || item?.key || "").trim(),
    year: "",
    verified: 0,
  };
  return renderHomeSongCard(previewSong, {
    href: String(item?.href || "#/").trim() || "#/",
    cardKind: "catalog-country",
    extraClass: `home-picker-card${item?.isActive ? " is-active" : ""}${extraClass ? ` ${extraClass}` : ""}`,
    previewLines: Array.isArray(item?.previewLines) ? item.previewLines : [],
    countLabel: item?.hideCount ? "" : homeCountrySongsCountLabel(item?.count),
  }).replace("<a ", `<a data-home-preview-card="1" data-home-bg="${esc(String(item?.previewBg || "").trim())}" `);
}

