function buildHomeSongSecondaryPreview(song = {}, options = {}) {
  const maxLines = Math.max(1, Number(options?.maxLines || 3));
  const matchBucket = String(song?.match_bucket || "").trim().toLowerCase();
  const matchReasons = Array.isArray(song?.match_reasons) ? song.match_reasons : [];
  const useSearchSnippet = matchBucket === "text"
    || matchBucket === "partial"
    || matchBucket === "fuzzy"
    || matchReasons.some((reason) => /^lyrics_/.test(String(reason || "")));
  const normalizePreviewLine = (value = "") => normalizeLyricsDisplayLine(value).replace(/\s+/g, " ").trim();
  const normalizePreviewCompare = (value = "") => normalizePreviewLine(value)
    .replace(/["'«»„“”‘’`]+/g, "")
    .toLowerCase();
  const hasTextOrDigit = (line = "") => /[\p{L}\p{N}]/u.test(String(line || ""));
  const isPreviewMetaLine = (line = "", titleNormalized = "") => {
    const normalized = normalizePreviewLine(line).toLowerCase();
    if (!normalized) return true;
    if (normalizePreviewCompare(normalized) === normalizePreviewCompare(titleNormalized)) return true;
    if (/^[\[(].*[\])]\s*$/.test(normalized)) return true;
    if (!hasTextOrDigit(normalized)) return true;
    if (/^(музыка|слова|музика|текст|исполнитель|исполняет|исп\.|виконує|виконавець|виконують|виконання|муз\.|сл\.|music|lyrics|words|performed by|composer|author)\s*[:.-]/i.test(normalized)) return true;
    if (/^(интродукция|інтродукція|вступ|вступление|куплет|припев|приспів|приспев|chorus|verse|bridge|intro|outro|проигрыш|програш|refren|refrain|refrään)\s*\d*\s*[:.-]?$/i.test(normalized)) return true;
    return false;
  };
  const titleNormalized = String(song?.title || "");
  const collectPreviewLines = (rawLines = []) => {
    const parts = [];
    let contentCount = 0;
    let pendingGap = false;
    let started = false;
    let hasMore = false;

    for (let index = 0; index < rawLines.length; index += 1) {
      const rawLine = String(rawLines[index] || "");
      const line = normalizePreviewLine(rawLine);
      if (!line) {
        if (started && contentCount > 0) pendingGap = true;
        continue;
      }
      if (isPreviewMetaLine(line, titleNormalized)) continue;
      if (!started) started = true;
      if (contentCount >= maxLines) {
        hasMore = true;
        break;
      }
      if (pendingGap && parts.length) {
        parts.push({ type: "gap" });
        pendingGap = false;
      }
      parts.push({ type: "line", text: line });
      contentCount += 1;
    }

    if (!hasMore) {
      let seenContent = 0;
      for (let index = 0; index < rawLines.length; index += 1) {
        const line = normalizePreviewLine(rawLines[index] || "");
        if (!line) continue;
        if (isPreviewMetaLine(line, titleNormalized)) continue;
        seenContent += 1;
        if (seenContent > contentCount) {
          hasMore = true;
          break;
        }
      }
    }

    return { parts, truncated: hasMore };
  };
  const rawSnippet = String(song?.snippet || "").replace(/\r\n?/g, "\n").trim();
  const snippetLines = useSearchSnippet && rawSnippet
    ? createLyricsDisplayEntries(rawSnippet).entries
      .map((entry) => normalizePreviewLine(entry.text))
      .filter((line) => !isPreviewMetaLine(line, titleNormalized))
    : [];
  if (snippetLines.length) {
    return collectPreviewLines(snippetLines);
  }

  return collectPreviewLines(createLyricsDisplayEntries(String(song?.lyrics || "")).entries.map((entry) => entry.text));
}

function normalizeSearchPreviewText(value = "") {
  return String(value || "")
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^\p{L}\p{N}]+/gu, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function tokenizeSearchPreviewQuery(value = "") {
  const rawTokens = String(value || "").match(/[\p{L}\p{N}]+/gu) || [];
  const out = [];
  const seen = new Set();
  for (const rawToken of rawTokens) {
    const raw = String(rawToken || "").trim();
    const normalized = normalizeSearchPreviewText(raw);
    if (!raw || !normalized || normalized.length < 2 || seen.has(normalized)) continue;
    seen.add(normalized);
    out.push({ raw, normalized });
  }
  return out;
}

function previewLineContainsSearchHit(line = "", queryTokens = []) {
  const normalizedLine = normalizeSearchPreviewText(line);
  if (!normalizedLine) return false;
  return queryTokens.some((token) => normalizedLine.includes(token.normalized));
}

function highlightPreviewSearchTerms(line = "", queryTokens = []) {
  if (!line || !queryTokens.length) return escDisplayText(line);
  const literalTokens = queryTokens
    .map((token) => String(token?.raw || "").trim())
    .filter((token) => token.length >= 2)
    .sort((left, right) => right.length - left.length);
  if (!literalTokens.length) return escDisplayText(line);
  const matches = [];
  for (const token of literalTokens) {
    const pattern = token.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const regex = new RegExp(pattern, "giu");
    let found;
    while ((found = regex.exec(line)) !== null) {
      const start = found.index;
      const end = start + found[0].length;
      if (matches.some((item) => !(end <= item.start || start >= item.end))) continue;
      matches.push({ start, end });
      if (regex.lastIndex === found.index) regex.lastIndex += 1;
    }
  }
  if (!matches.length) return escDisplayText(line);
  matches.sort((left, right) => left.start - right.start || right.end - left.end);
  let html = "";
  let cursor = 0;
  for (const match of matches) {
    if (match.start < cursor) continue;
    html += escDisplayText(line.slice(cursor, match.start));
    html += `<mark class="yt-card-search-hit">${escDisplayText(line.slice(match.start, match.end))}</mark>`;
    cursor = match.end;
  }
  html += escDisplayText(line.slice(cursor));
  return html;
}

function resolveHomeCardPreviewLineLimit(options = {}) {
  if (typeof window === "undefined") return 3;
  const width = Math.max(0, Number(window.innerWidth || 0));
  if (width <= 960) return 2;
  return 3;
}

function renderHomeSongSecondary(song = {}, options = {}) {
  const maxLines = Math.max(2, Number(options.maxLines || resolveHomeCardPreviewLineLimit(options)));
  const preview = buildHomeSongSecondaryPreview(song, { maxLines });
  if (!Array.isArray(preview.parts) || !preview.parts.length) return "";
  const queryTokens = tokenizeSearchPreviewQuery(options.searchQuery || "");
  const allowSearchHighlight = queryTokens.length > 0 && (
    String(song?.match_bucket || "").trim().toLowerCase() === "text" ||
    (Array.isArray(song?.match_reasons) && song.match_reasons.some((reason) => /^lyrics_/.test(String(reason || ""))))
  );
  let lastLineIndex = -1;
  preview.parts.forEach((part, index) => {
    if (part?.type === "line") lastLineIndex = index;
  });
  return preview.parts.map((part, index) => {
    if (part?.type === "gap") return `<span class="yt-card-performer-gap" aria-hidden="true"></span>`;
    const text = String(part?.text || "").trim();
    if (!text) return "";
    const withEllipsis = preview.truncated && index === lastLineIndex ? `${text}...` : text;
    const html = allowSearchHighlight && previewLineContainsSearchHit(text, queryTokens)
      ? highlightPreviewSearchTerms(withEllipsis, queryTokens)
      : escDisplayText(withEllipsis);
    return `<span class="yt-card-performer-line">${html}</span>`;
  }).join("");
}

function renderHomeSongCard(song = {}, options = {}) {
  const backgroundsByCountry = options.backgroundsByCountry instanceof Map ? options.backgroundsByCountry : new Map();
  const cardKind = String(options.cardKind || "song").trim().toLowerCase();
  const isPickerCard = cardKind === "picker";
  const isHistoricalCountryCard = cardKind === "historical-country";
  const isCatalogCountryCard = cardKind === "catalog-country";
  const flagDevice = options.flagDevice || preferredFlagCardDevice();
  const isVerified = Number(song?.verified || 0) === 1;
  const showFavoriteBadge = options.favoriteBadge === true;
  const countryKey = normalizeSongCountry(song?.country || "");
  const background = countryKey ? (backgroundsByCountry.get(countryKey) || {}) : {};
  const overrideFlagUrl = String(options.flagUrl || "").trim();
  const resolvedLongFlagUrl = resolveVisualSymbolUrl(background?.visual_profile || {}, {
    year: song?.year || "",
    kind: "long",
    device: flagDevice,
  });
  const resolvedSquareFlagUrl = resolveVisualSymbolUrl(background?.visual_profile || {}, {
    year: song?.year || "",
    kind: "square",
    device: flagDevice,
  });
  const flagUrl = overrideFlagUrl || resolvedLongFlagUrl || resolvedSquareFlagUrl;
  const hasFlag = !!flagUrl;
  const hasSideFlag = false;
  const previewLineLimit = resolveHomeCardPreviewLineLimit();
  const secondaryText = renderHomeSongSecondary(song, {
    hasFlag: hasSideFlag,
    maxLines: previewLineLimit,
    searchQuery: options.searchQuery || "",
  });
  const catalogPreviewText = isCatalogCountryCard
    ? (Array.isArray(options.previewLines) ? options.previewLines : [])
      .map((line) => String(line || "").trim())
      .filter(Boolean)
      .join("\n")
    : "";
  const catalogCountLabel = isCatalogCountryCard ? String(options.countLabel || "").trim() : "";
  const flagStyle = hasSideFlag ? ` style="${esc(`--yt-card-flag-image:${toCssUrlValue(flagUrl)}`)}"` : "";
  const yearValue = isPickerCard ? "" : getPublicSongYear(song?.year || "");
  const langValue = isPickerCard ? "" : String(song?.lang ? formatLang(song.lang) : "").trim();
  const countryValue = isPickerCard ? "" : compactHistoricalCountryLabel(song?.country || "");
  const periodValue = isPickerCard ? "" : compactHistoricalPeriodLabel(song?.period || "");
  const historicalMeta = isHistoricalCountryCard ? (options?.historicalMeta || getHistoricalAffiliationMeta(song?.country || "")) : null;
  const historicalEyebrow = isHistoricalCountryCard ? historicalCountryCardEyebrow(historicalMeta?.kind || "state") : "";
  const mainMetaParts = [
    yearValue ? `<span class="yt-card-main-meta-part yt-card-main-meta-year">${esc(yearValue)}</span>` : "",
    langValue ? `<span class="yt-card-main-meta-part yt-card-main-meta-soft">${esc(langValue)}</span>` : "",
    periodValue
      ? renderMetaLabelPart(periodValue, "yt-card-main-meta-part yt-card-main-meta-soft")
      : (countryValue ? renderMetaLabelPart(countryValue, "yt-card-main-meta-part yt-card-main-meta-soft") : ""),
  ].filter(Boolean);
  const mainMeta = mainMetaParts.length ? `<div class="yt-card-main-meta">${mainMetaParts.join("")}</div>` : ``;
  /*
      <span class="yt-card-line">${esc(metaParts.join(" · "))}</span>
    </div>
  ` : ``;
  */
  const sideRail = `
    <div class="yt-card-side ${hasFlag ? "yt-card-side-flag" : "yt-card-side-plain"}">
      ${hasFlag ? `<div class="yt-card-flag-wrap"><span class="yt-card-flag"${flagStyle}></span></div>` : ``}
    </div>
  `;
  const matchedVersionId = normalizeVersionIdentifier(song?.matched_version_id);
  const defaultHref = matchedVersionId
    ? makeHash(`#/song/${encodeURIComponent(song.id)}`, { version: matchedVersionId }, ["version"])
    : `#/song/${encodeURIComponent(song.id)}`;
  const href = String(options.href || defaultHref).trim() || "#/";
  const extraClass = String(options.extraClass || "").trim();
  const inlineStyle = String(options.inlineStyle || "").trim();
  const historicalCountNumber = formatUiInteger(song?.count || 0);
  const historicalCountLabel = homeCountrySongsCountLabel(song?.count || 0).replace(/^\s*\d+[\s\u00A0]*/u, "").trim();
  const cardClassName = [
    "yt-card",
    hasSideFlag ? "yt-card-has-flag" : "",
    isHistoricalCountryCard ? "yt-card-historical-country" : "",
    isCatalogCountryCard ? "yt-card-catalog-country" : "",
    `yt-card-preview-${previewLineLimit}`,
    extraClass,
  ]
    .filter(Boolean)
    .join(" ");
  const historicalBody = isHistoricalCountryCard ? `
      <div class="yt-card-historical-shell">
        <div class="yt-card-historical-media">
          ${hasFlag ? `<img class="yt-card-historical-media-image" src="${esc(flagUrl)}" alt="" loading="lazy" decoding="async" />` : `<span class="yt-card-historical-media-image yt-card-historical-media-image-fallback" aria-hidden="true"></span>`}
          <span class="yt-card-historical-media-overlay" aria-hidden="true"></span>
        </div>
        <div class="yt-card-historical-body">
          <div class="yt-card-historical-heading">
            <div class="yt-card-title">${escDisplayText(song.title)}</div>
            <div class="yt-card-historical-era">${esc(getPublicSongYear(song?.year || ""))}</div>
          </div>
          <div class="yt-card-historical-count" aria-label="${esc(homeCountrySongsCountLabel(song?.count || 0))}">
            <span class="yt-card-historical-count-value">${esc(historicalCountNumber)}</span>
            <span class="yt-card-historical-count-label">${esc(historicalCountLabel || (uiLocale() === "ru" ? "песен" : uiLocale() === "uk" ? "пісень" : uiLocale() === "et" ? "laulu" : "songs"))}</span>
          </div>
        </div>
      </div>
  ` : "";
  return `
    <a class="${esc(cardClassName)}" href="${esc(href)}"${inlineStyle ? ` style="${esc(inlineStyle)}"` : ""}>
      ${showFavoriteBadge ? `<span class="yt-card-fav-badge">${esc(favoriteBadgeLabel())}</span>` : ``}
      ${isHistoricalCountryCard ? historicalBody : `
      <div class="yt-card-content">
        <div class="yt-card-title-row">
          <div class="yt-card-title">${escDisplayText(song.title)}</div>
          ${isVerified ? `<div class="yt-card-title-badges"><span class="yt-card-verified">${esc(verifiedLabel())}</span></div>` : ``}
        </div>
        ${isCatalogCountryCard
          ? `${catalogPreviewText ? `<div class="yt-card-country-preview">${esc(catalogPreviewText)}</div>` : ``}
             ${catalogCountLabel ? `<div class="yt-card-country-count">${esc(catalogCountLabel)}</div>` : ``}`
          : `${mainMeta}
             ${secondaryText ? `<div class="yt-card-performer">${secondaryText}</div>` : ``}`
        }
      </div>`}
      ${isHistoricalCountryCard ? "" : sideRail}
    </a>
  `;
}

function renderHomeSongCardFallback(song = {}, options = {}) {
  const matchedVersionId = normalizeVersionIdentifier(song?.matched_version_id);
  const defaultHref = matchedVersionId
    ? makeHash(`#/song/${encodeURIComponent(song?.id || "")}`, { version: matchedVersionId }, ["version"])
    : `#/song/${encodeURIComponent(song?.id || "")}`;
  const href = String(options.href || defaultHref).trim() || "#/";
  const yearValue = getPublicSongYear(song?.year || "");
  const langValue = String(song?.lang ? formatLang(song.lang) : "").trim();
  const countryValue = compactHistoricalCountryLabel(song?.country || "");
  const periodValue = compactHistoricalPeriodLabel(song?.period || "");
  const datedMetaValue = periodValue || countryValue;
  return `
    <a class="yt-card yt-card-preview-3" href="${esc(href)}">
      <div class="yt-card-content">
        <div class="yt-card-title-row">
          <div class="yt-card-title">${escDisplayText(String(song?.title || "").trim() || "Untitled")}</div>
        </div>
        ${(yearValue || langValue || datedMetaValue) ? `<div class="yt-card-main-meta">
          ${yearValue ? `<span class="yt-card-main-meta-part yt-card-main-meta-soft">${esc(yearValue)}</span>` : ""}
          ${langValue ? `<span class="yt-card-main-meta-part yt-card-main-meta-soft">${esc(langValue)}</span>` : ""}
          ${datedMetaValue ? renderMetaLabelPart(datedMetaValue, "yt-card-main-meta-part yt-card-main-meta-soft") : ""}
        </div>` : ``}
      </div>
      <div class="yt-card-side yt-card-side-plain"></div>
    </a>
  `;
}

function renderHomeSongCardSafe(song = {}, options = {}) {
  try {
    return renderHomeSongCard(song, options);
  } catch (error) {
    try {
      console.error("Home song card render failed", song?.id || song?.title || song, error);
    } catch {}
    return renderHomeSongCardFallback(song, options);
  }
}

function renderHomeResultsFeedItems(items = [], options = {}) {
  const showGroupTitles = options?.showGroupTitles !== false;
  const bucketCounts = options?.bucketCounts && typeof options.bucketCounts === "object"
    ? options.bucketCounts
    : {};
  const resolveBucketCount = (bucket = "", fallback = 0) => {
    const safeBucket = String(bucket || "").trim().toLowerCase();
    if (safeBucket && Number.isFinite(Number(bucketCounts[safeBucket]))) {
      return Math.max(0, Number(bucketCounts[safeBucket]) || 0);
    }
    if (safeBucket === "exact_title" && Number.isFinite(Number(bucketCounts.exact))) {
      return Math.max(0, Number(bucketCounts.exact) || 0);
    }
    return Math.max(0, Number(fallback || 0) || 0);
  };
  if (!showGroupTitles) {
    return items.map((song, index) => `
      <div class="home-result-item" style="--result-index:${Math.min(index, 6)}">${renderHomeSongCardSafe(song, options)}</div>
    `).join("");
  }
  const groups = [];
  for (const song of items) {
    const bucket = String(song?.match_bucket || "exact").trim().toLowerCase() || "exact";
    const last = groups[groups.length - 1];
    if (!last || last.bucket !== bucket) groups.push({ bucket, items: [] });
    groups[groups.length - 1].items.push(song);
  }
  return groups.map((group) => `
    <section class="home-result-group" data-bucket="${esc(group.bucket)}">
      <div class="home-result-group-title">${esc(searchBucketLabel(group.bucket))}: <span class="home-result-group-count">${esc(resolveBucketCount(group.bucket, group.items.length))}</span></div>
      ${group.items.map((song, index) => `<div class="home-result-item" style="--result-index:${Math.min(index, 6)}">${renderHomeSongCardSafe(song, options)}</div>`).join("")}
    </section>
  `).join("");
}

function homeUI(data, params, homeExtras = {}) {
  const page = data.page || 1;
  const pages = data.pages || 1;
  const q = params.q || "";
  const lang = normalizeSongLanguage(params.lang || "") || params.lang || "";
  const selectedEntityName = String(params.entity || "").trim();
  const country = normalizeSongCountry(params.country || "") || params.country || "";
  const countrySelection = resolveHistoricalAffiliationSelection(country || "");
  const period = normalizeSongPeriod(params.period || "") || params.period || "";
  const theme = String(params.theme || "").trim();
  const wordsAuthor = String(params.words_author || "").trim();
  const musicAuthor = String(params.music_author || "").trim();
  const verified = String(params.verified || "").trim() === "1";
  const recent = String(params.recent || "").trim() === "1";
  const multiVersions = String(params.multi_versions || "").trim() === "1";
  const performer = params.performer || "";
  const year = params.year || "";
  const hasTextQuery = String(q || "").trim().length > 0;
  const didSearch = params.searched === "1" || hasHomeSearchIntent(params);
  const lockedCountry = normalizeSongCountry(country || "") || "";
  const isCountryLocked = !!lockedCountry;
  const hasAdvancedValue = !!(wordsAuthor || musicAuthor || verified || multiVersions || performer || year);
  const showAdvanced = params.adv === "1" || (!isCountryLocked && hasAdvancedValue);
  const advancedLabel = t("topSearch.advanced");
  const hideAdvancedLabel = t("topSearch.advancedHide");
  const recentEntryHref = catalogHashForSongFilter({
    q: "",
    lang: "",
    country: "",
    words_author: "",
    music_author: "",
    verified: "",
    recent: "1",
    multi_versions: "",
    performer: "",
    year: "",
    searched: "1",
    adv: "0",
    page: "1",
  });
  const backgroundsByCountry = new Map();
  const directCountryCounts = new Map();
  const countryCounts = new Map();
  const countItems = Array.isArray(homeExtras?.countryCounts) ? homeExtras.countryCounts : [];
  for (const item of countItems) {
    const key = normalizeSongCountry(item?.country || "");
    const count = Number(item?.count || 0);
    if (!key || count < 0) continue;
    directCountryCounts.set(key, (directCountryCounts.get(key) || 0) + count);
    for (const rollupCountry of entityRollupCountriesFor(key)) {
      countryCounts.set(rollupCountry, (countryCounts.get(rollupCountry) || 0) + count);
    }
  }
  const backgroundItems = Array.isArray(homeExtras?.countryBackgrounds) ? homeExtras.countryBackgrounds : [];
  for (const item of backgroundItems) {
    const normalized = normalizeCountryBackground(item, item?.country || "");
    const key = normalizeSongCountry(normalized?.country || "");
    if (!key || backgroundsByCountry.has(key)) continue;
    backgroundsByCountry.set(key, normalized);
  }

  const langCountryMap = new Map();
  const directLangCountryMap = new Map();
  const directLangTotals = new Map();
  const langCountryItems = Array.isArray(homeExtras?.langCountryCounts) ? homeExtras.langCountryCounts : [];
  for (const item of langCountryItems) {
    const langKey = normalizeSongLanguage(item?.lang || "");
    const countryKey = normalizeSongCountry(item?.country || "");
    const count = Number(item?.count || 0);
    if (!langKey || count <= 0) continue;
    if (!langCountryMap.has(langKey)) {
      langCountryMap.set(langKey, { total: 0, countries: new Map() });
    }
    if (!directLangCountryMap.has(langKey)) {
      directLangCountryMap.set(langKey, new Map());
    }
    if (countryKey) {
      const directCountries = directLangCountryMap.get(langKey);
      directCountries.set(countryKey, (directCountries.get(countryKey) || 0) + count);
    }
    const bucket = langCountryMap.get(langKey);
    directLangTotals.set(langKey, (directLangTotals.get(langKey) || 0) + count);
    bucket.total = directLangTotals.get(langKey) || 0;
    for (const rollupCountry of entityRollupCountriesFor(countryKey)) {
      bucket.countries.set(rollupCountry, (bucket.countries.get(rollupCountry) || 0) + count);
    }
  }

  const langCountryPeriodItems = Array.isArray(homeExtras?.langCountryPeriodCounts) ? homeExtras.langCountryPeriodCounts : [];
  const langCountryPeriodMap = new Map();
  for (const item of langCountryPeriodItems) {
    const langKey = normalizeSongLanguage(item?.lang || "");
    const countryKey = normalizeSongCountry(item?.country || "");
    const periodKey = normalizeSongPeriod(item?.period || "");
    const count = Number(item?.count || 0);
    if (!langKey || !countryKey || !periodKey || count <= 0) continue;
    for (const rollupCountry of entityRollupCountriesFor(countryKey)) {
      const key = `${langKey}::${rollupCountry}`;
      if (!langCountryPeriodMap.has(key)) langCountryPeriodMap.set(key, new Map());
      const periodMap = langCountryPeriodMap.get(key);
      periodMap.set(periodKey, (periodMap.get(periodKey) || 0) + count);
    }
  }
  const availableCountriesByLang = buildLangCountryAvailabilityMap(langCountryItems);
  const availablePeriodsByLangCountry = buildLangCountryPeriodAvailabilityMap(langCountryPeriodItems);

  const localeForSort = uiLocale() === "ru" ? "ru" : uiLocale() === "uk" ? "uk" : uiLocale() === "et" ? "et" : "en";
  const periodOrderMap = new Map(
    getCatalogOptions("period", uiLocale(), "")
      .map((option, index) => [String(option?.value || "").trim(), index])
  );
  const totalSongsFromResults = Math.max(0, Number(data?.total || 0));
  const totalSongsFromCountries = Array.from(directCountryCounts.values()).reduce((sum, count) => sum + Math.max(0, Number(count || 0)), 0);
  const totalSongsOnSite = Math.max(totalSongsFromResults, totalSongsFromCountries);
  const compareCountries = (left, right) => {
    const leftOther = normalizeSongCountry(left?.key || "") === "other_countries" ? 1 : 0;
    const rightOther = normalizeSongCountry(right?.key || "") === "other_countries" ? 1 : 0;
    return leftOther - rightOther
      || Number(left?.sortOrder || 0) - Number(right?.sortOrder || 0)
      || String(left?.title || "").localeCompare(String(right?.title || ""), localeForSort)
      || (Number(right?.count || 0) - Number(left?.count || 0));
  };
  const compareHistoricalChronology = (left, right) => {
    const leftYears = historicalYearsMeta(left?.key || left?.country || "", left?.label || left?.title || "");
    const rightYears = historicalYearsMeta(right?.key || right?.country || "", right?.label || right?.title || "");
    const leftHasYears = Number(leftYears.start) < Number.MAX_SAFE_INTEGER;
    const rightHasYears = Number(rightYears.start) < Number.MAX_SAFE_INTEGER;
    if (leftHasYears !== rightHasYears) return leftHasYears ? -1 : 1;
    return Number(leftYears.start || 0) - Number(rightYears.start || 0)
      || Number(leftYears.end || 0) - Number(rightYears.end || 0)
      || compareCountries(left, right);
  };
  const languageCards = Array.from(langCountryMap.entries())
    .map(([langKey, bucket]) => {
      const rankedCountries = Array.from(bucket.countries.entries())
        .sort((a, b) => b[1] - a[1] || formatCountry(a[0]).localeCompare(formatCountry(b[0]), localeForSort));
      const topCountriesLabel = rankedCountries
        .slice(0, 2)
        .map(([countryKey]) => formatCountry(countryKey))
        .filter(Boolean)
        .join(" · ");
      const href = catalogHashForSongFilter({ lang: langKey, searched: "0", adv: "0", page: "1" });
      return {
        key: langKey,
        label: formatLang(langKey),
        title: formatLang(langKey),
        count: bucket.total,
        href,
        lang: langKey,
        previewLines: [
          homePickerDetailLine(t("home.country"), topCountriesLabel),
          homeCountrySongsCountLabel(bucket.total),
          homeOpenNavigationLabel(),
        ],
        isActive: lang === langKey && !country,
      };
    })
    .filter((item) => Number(item?.count || 0) >= HOME_MENU_MIN_SONGS)
    .sort((a, b) => (Number(b.count) || 0) - (Number(a.count) || 0) || a.title.localeCompare(b.title, localeForSort));

  const selectedLangBucket = lang ? langCountryMap.get(lang) : null;
  const selectedLangCountryCards = selectedLangBucket
    ? Array.from(selectedLangBucket.countries.entries())
      .map(([countryKey, totalCount]) => {
        const background = backgroundsByCountry.get(countryKey) || {};
        const previewYear = historicalFlagYear(countryKey, formatCountry(countryKey));
        const resolvedBackground = normalizeCountryBackground(background, countryKey, { year: previewYear });
        const countryTitle = historicalCardTitle(
          formatCountry(countryKey),
          historicalYearsMeta(countryKey, formatCountry(countryKey)).display
        );
        const yearsLabel = historicalYearsMeta(countryKey, formatCountry(countryKey)).display;
        const inlineLabel = [countryTitle, yearsLabel, homeCountrySongsCountLabel(totalCount)]
          .map((part) => String(part || "").trim())
          .filter(Boolean)
          .join(". ");
        const flagUrl = resolveVisualSymbolUrl(resolvedBackground?.visual_profile || {}, {
          year: previewYear,
          kind: "square",
          device: "desktop",
        });
        const periodEntries = Array.from(langCountryPeriodMap.get(`${lang}::${countryKey}`)?.entries() || [])
          .filter(([periodKey, count]) => !!normalizeSongPeriod(periodKey || "") && Number(count || 0) > 0)
          .sort((a, b) => {
            const leftIndex = periodOrderMap.has(a[0]) ? Number(periodOrderMap.get(a[0])) : Number.MAX_SAFE_INTEGER;
            const rightIndex = periodOrderMap.has(b[0]) ? Number(periodOrderMap.get(b[0])) : Number.MAX_SAFE_INTEGER;
            return leftIndex - rightIndex
              || (Number(b[1] || 0) - Number(a[1] || 0))
              || formatPeriod(a[0]).localeCompare(formatPeriod(b[0]), localeForSort);
          });
        return {
          key: countryKey,
          label: inlineLabel,
          title: inlineLabel,
          count: totalCount,
          href: catalogHashForSongFilter({ lang, country: countryKey, searched: periodEntries.length ? "0" : "1", adv: "0", page: "1" }),
          previewBg: String(resolvedBackground?.desktop_image_url || resolvedBackground?.mobile_image_url || "").trim(),
          wallBg: String(resolvedBackground?.desktop_image_url || resolvedBackground?.mobile_image_url || "").trim(),
          flagBg: flagUrl,
          hideCount: true,
          lang,
          country: countryKey,
          isActive: country === countryKey && !didSearch,
          sortOrder: homePickerCountrySortOrder(countryKey),
        };
      })
      .sort((a, b) => (Number(b?.count || 0) - Number(a?.count || 0)) || compareCountries(a, b))
    : [];
  const selectedLangEntityNavigationHtml = "";

  const selectedCountryPeriodCards = (lang && country)
    ? Array.from(langCountryPeriodMap.get(`${lang}::${country}`)?.entries() || [])
      .filter(([periodKey, totalCount]) => !!normalizeSongPeriod(periodKey || "") && Number(totalCount || 0) > 0)
      .map(([periodKey, totalCount]) => {
        const background = backgroundsByCountry.get(country) || {};
        const previewYear = representativeYearForPeriod(periodKey);
        const resolvedBackground = normalizeCountryBackground(background, country, { year: previewYear });
        const wallpaperUrl = String(resolvedBackground?.desktop_image_url || resolvedBackground?.mobile_image_url || "").trim();
        const flagUrl = resolveVisualSymbolUrl(resolvedBackground?.visual_profile || {}, {
          year: previewYear,
          kind: "square",
          device: "desktop",
        });
        return {
          key: periodKey,
          label: formatPeriod(periodKey),
          title: formatPeriod(periodKey),
          count: totalCount,
          href: catalogHashForSongFilter({ lang, country, period: periodKey, searched: "1", adv: "0", page: "1" }),
          previewBg: wallpaperUrl,
          wallBg: wallpaperUrl,
          flagBg: flagUrl,
          lang,
          country,
          previewLines: [
            homePickerDetailLine(t("home.country"), formatCountry(country)),
            homeCountrySongsCountLabel(totalCount),
          ],
          isActive: period === periodKey && !didSearch,
          sortOrder: periodOrderMap.has(periodKey) ? Number(periodOrderMap.get(periodKey)) : Number.MAX_SAFE_INTEGER,
        };
      })
      .sort((a, b) => Number(a?.sortOrder || 0) - Number(b?.sortOrder || 0) || a.title.localeCompare(b.title, localeForSort))
    : [];

  const languageCardsHtml = languageCards.length
    ? languageCards.map((item) => renderHomeCatalogCard(item)).join("")
    : ``;

  const navigationDirectCounts = lang
    ? (directLangCountryMap.get(lang) || new Map())
    : directCountryCounts;
  const homeTopNavigationHtml = renderHomeTopNavigation(navigationDirectCounts, lang);
  const selectedEntityState = selectedEntityName
    ? homeEntityBranchState(selectedEntityName, navigationDirectCounts)
    : { count: 0, children: [] };
  const selectedEntityHasChildren = selectedEntityState.children.length > 0;
  const selectedEntityBranchHtml = selectedEntityName
    ? renderHomeEntityBranch(selectedEntityName, navigationDirectCounts, lang, params.path || "")
    : "";

  const selectedLanguageCountryCardsHtml = selectedLangCountryCards.length
    ? selectedLangCountryCards.map((item) => renderHomeCatalogCard(item)).join("")
    : ``;

  const selectedCountryPeriodCardsHtml = selectedCountryPeriodCards.length
    ? selectedCountryPeriodCards.map((item) => renderHomeCatalogCard(item)).join("")
    : "";

  const showNavigationRoot = !didSearch && !isCountryLocked && !selectedEntityName;
  const showEntityBranch = !didSearch && !isCountryLocked && !!selectedEntityName;
  const showLanguageRoot = false;
  const showLanguageCountryPicker = false;
  const showLanguagePeriodPicker = !didSearch && !!lang && !!country && !period && selectedCountryPeriodCards.length > 0;
  const shouldShowResults = didSearch
    || (!!selectedEntityName && !selectedEntityHasChildren)
    || (!!lang && !!country && !!period)
    || (!!lang && !!country && selectedCountryPeriodCards.length === 0);
  const showPassiveHint = !showNavigationRoot && !showEntityBranch && !showLanguageRoot && !showLanguageCountryPicker && !showLanguagePeriodPicker;
  const resultsContextLabel = shouldShowResults
    ? (selectedEntityName && !selectedEntityHasChildren
      ? homeEntityDetailedLabel(selectedEntityName)
      : fullHistoricalCountryDisplayLabel(country))
    : "";

  const loadingResultsText = homeLoadingResultsText();
  const resultLoadingScreenMarkup = `
    <div class="card home-search-hint home-results-loader-screen" id="yt_results_loading_screen">
      <div class="home-results-loader-row">
        <span class="home-results-spinner" aria-hidden="true"></span>
        <span class="muted">${esc(loadingResultsText)}</span>
      </div>
    </div>
  `;
  const hasExactResults = (data.items || []).length > 0;
  const bucketSummaryMarkup = hasTextQuery
    ? renderSearchBucketSummary(data?.bucket_counts || {})
    : "";
  const maybeYouSearchedTitle = uiLocale() === "ru"
    ? "\u0412\u043e\u0437\u043c\u043e\u0436\u043d\u043e, \u0432\u044b \u0438\u0441\u043a\u0430\u043b\u0438"
    : uiLocale() === "uk"
      ? "\u041c\u043e\u0436\u043b\u0438\u0432\u043e, \u0432\u0438 \u0448\u0443\u043a\u0430\u043b\u0438"
      : uiLocale() === "et"
        ? "Võib-olla otsisite"
        : "Maybe you searched for";
  const exactNotFoundText = uiLocale() === "ru"
    ? "\u0422\u043e\u0447\u043d\u043e\u0433\u043e \u0441\u043e\u0432\u043f\u0430\u0434\u0435\u043d\u0438\u044f \u043d\u0435 \u043d\u0430\u0439\u0434\u0435\u043d\u043e."
    : uiLocale() === "uk"
      ? "\u0422\u043e\u0447\u043d\u043e\u0433\u043e \u0437\u0431\u0456\u0433\u0443 \u043d\u0435 \u0437\u043d\u0430\u0439\u0434\u0435\u043d\u043e."
      : uiLocale() === "et"
        ? "Täpset vastet ei leitud."
        : "No exact match found.";

  return `
    <section class="yt-main home-main ${shouldShowResults ? "is-search-results" : ""}">
      <div class="yt-chips ${showAdvanced ? "is-open" : "hidden"}" id="yt_advancedPanel">
        <input id="yt_recent_mode" type="hidden" value="${recent ? "1" : ""}" />
        <label class="yt-chip-input">
          <span>${esc(t("field.lang"))}</span>
          <select class="select" id="yt_lang">${selectOptions("language", lang, uiText("selectLanguage"))}</select>
        </label>
        ${isCountryLocked ? `<input id="yt_country" type="hidden" value="${esc(lockedCountry)}" />` : `
        <label class="yt-chip-input">
          <span>${esc(historicalAffiliationFieldLabel())}</span>
          <select class="select" id="yt_country">${historicalAffiliationSelectOptions(lang || countrySelection.lang || "", "", country || "", {
            allowedCountries: availableCountriesByLang.get(lang || countrySelection.lang || "") || null,
          })}</select>
        </label>
        `}
        <label class="yt-chip-input">
          <span>${esc(uiText("performer"))}</span>
          <input class="input" id="yt_performer" value="${esc(performer)}" />
        </label>
        <label class="yt-chip-input">
          <span>${esc(t("field.words"))}</span>
          <input class="input" id="yt_words_author" value="${esc(wordsAuthor)}" />
        </label>
        <label class="yt-chip-input">
          <span>${esc(t("field.music"))}</span>
          <input class="input" id="yt_music_author" value="${esc(musicAuthor)}" />
        </label>
        <div class="yt-chip-checkboxes">
          <label class="yt-chip-input yt-chip-checkbox">
            <div class="checkbox-row">
              <input type="checkbox" id="yt_verified" ${verified ? "checked" : ""} />
              <span>${esc(verifiedOnlyLabel())}</span>
            </div>
          </label>
          <label class="yt-chip-input yt-chip-checkbox">
            <div class="checkbox-row">
              <input type="checkbox" id="yt_multi_versions" ${multiVersions ? "checked" : ""} />
              <span>${esc(multiVersionsOnlyLabel())}</span>
            </div>
          </label>
        </div>
        <label class="yt-chip-input">
          <span>${esc(t("field.year"))}</span>
          <input class="input" id="yt_year" value="${esc(year)}" />
        </label>
        <div class="actions home-advanced-actions">
          <button class="btn primary" id="yt_applyAdvanced" type="button">${esc(t("common.search"))}</button>
          <button class="btn ghost" id="yt_resetAdvanced" type="button">${esc(t("common.reset"))}</button>
        </div>
      </div>

      ${showNavigationRoot ? `<div class="home-country-head">
        <div class="home-country-head-main">
          ${homeCurrentUserDisplayName() ? `<div class="home-user-account">
            <button class="home-user-account-button" id="homeUserAccountButton" type="button" aria-haspopup="menu" aria-expanded="false">
              <span class="h1 home-user-title">${esc(homeCurrentUserDisplayName())}</span>
              <span class="home-user-account-caret" aria-hidden="true"></span>
            </button>
            <div class="home-user-account-menu hidden" id="homeUserAccountMenu" role="menu">
              <button class="home-user-account-item" id="homeUserChangeNickname" type="button" role="menuitem">${esc(t("profile.changeNickname"))}</button>
              <button class="home-user-account-item" id="homeUserLogout" type="button" role="menuitem">${esc(t("auth.logout"))}</button>
            </div>
          </div>` : ""}
          ${totalSongsOnSite > 0 ? `<div class="home-catalog-total" aria-label="${esc(homeCatalogTotalLabel())}">
            <span class="home-catalog-total-value">${esc(formatUiInteger(totalSongsOnSite))}</span>
            <span class="home-catalog-total-label">${esc(homeCatalogTotalLabel())}</span>
          </div>` : ""}
        </div>
      </div>

      <div class="home-entity-nav">
        ${homeTopNavigationHtml}
      </div>` : ``}

      ${showEntityBranch ? selectedEntityBranchHtml : ``}

      ${showLanguageCountryPicker ? `<div class="home-country-head">
        <div>
          <div class="h1">${esc(homeLanguageCountriesTitle(formatLang(lang)))}</div>
        </div>
      </div>

      <div class="home-entity-nav">
        ${selectedLangEntityNavigationHtml}
      </div>` : ``}

      ${showLanguagePeriodPicker ? `<div class="home-country-head">
        <div>
          <div class="h1">${esc(homeLanguagePeriodsTitle(formatLang(lang), formatCountry(country)))}</div>
          <div class="muted">${esc(homeLanguagePeriodsHint())}</div>
        </div>
      </div>

      <div class="home-country-grid home-country-feed">
        ${selectedCountryPeriodCardsHtml}
      </div>` : ``}

      ${shouldShowResults ? `
        <div class="yt-feed-head yt-results-head">
          <div>
            ${resultsContextLabel ? `<div class="h1">${renderDisplayLabel(resultsContextLabel, {
              wrapperClass: "display-label",
              textClass: "display-label-text",
              rangeClass: "display-label-range",
            })}</div>
            <div class="muted">${esc(homeResultsContextSubtitle())}</div>` : `<div class="h1">${esc(homeResultsTitle())}</div>`}
          </div>
        </div>
        ${hasExactResults ? `
          ${bucketSummaryMarkup}
          ${resultLoadingScreenMarkup}
          <div class="yt-feed yt-feed-progressive is-chunk-loading" id="yt_results_feed" data-feed-mode="exact">
          </div>
          ${renderPager("yt", page, pages)}
        ` : `
          <div class="yt-feed">
            <div class="card"><div class="muted">${esc(t("home.nothing"))}</div><div class="actions" style="margin-top:10px"><a class="btn ghost" href="${esc(makeHash("#/fragment-reports", { new: "1", fragment: q || "" }, ["new", "fragment"]))}">${esc(homeReportFragmentLabel())}</a></div></div>
          </div>
        `}
      ` : showPassiveHint ? `
        <div class="card home-search-hint home-search-hint-flat">
          <div class="muted">${esc(homeSearchHintText())}</div>
        </div>
      ` : ``}
    </section>
  <div class="yt-mobile-spacer"></div>
  `;
}

