function draftVariantTypeLabel(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "suggested") return draftUiText("variantBadgeSuggested");
  if (normalized === "conflict") return draftUiText("variantBadgeConflict");
  return draftUiText("variantBadgeManual");
}

function draftConfidenceLevel(value, fallback = "exact") {
  return confidenceLevelFromValue(value, fallback);
}

function draftConfidenceBand(confidence) {
  return `is-confidence-${draftConfidenceLevel(confidence)}`;
}

function draftConfidenceDetails(confidence) {
  return confidenceLevelDetails(draftConfidenceLevel(confidence));
}

function draftConfidenceStyleValue(confidence) {
  const details = draftConfidenceDetails(confidence);
  return `--confidence-fill:${details.fill}%;--confidence-fill-factor:${(details.fill / 100).toFixed(3)};--confidence-shade:${details.shade};--confidence-border:${details.border};`;
}

function draftClampConfidence(value, fallback = 100) {
  return normalizeConfidenceValue(value, fallback);
}

function draftConfidenceFromInput(rawValue, fallback = 100) {
  return normalizeConfidenceValue(rawValue, fallback);
}

function draftConfidenceLabel(value) {
  const level = draftConfidenceLevel(value, "exact");
  if (level === "very_sure") return draftUiText("confidenceLevelVerySure");
  if (level === "sure") return draftUiText("confidenceLevelSure");
  if (level === "medium") return draftUiText("confidenceLevelMedium");
  if (level === "unsure") return draftUiText("confidenceLevelUnsure");
  return draftUiText("confidenceLevelExact");
}

function draftIsCompactMobileViewport() {
  try {
    return !!window.matchMedia?.("(max-width: 760px)").matches;
  } catch {
    return false;
  }
}

function draftCompactConfidenceLabel(value) {
  const level = draftConfidenceLevel(value, "exact");
  if (level === "very_sure") return "90%";
  if (level === "sure") return "75%";
  if (level === "medium") return "50%";
  if (level === "unsure") return "25%";
  return "100%";
}

function draftConfidencePercent(value, fallback = 100) {
  return `${draftClampConfidence(value, fallback)}%`;
}

function draftLineNumberLabel(number) {
  return draftUiText("lineNumberLabel", { number: Math.max(1, Number(number) || 1) });
}

function draftVariantNumberLabel(number) {
  return draftUiText("variantNumberLabel", { number: Math.max(1, Number(number) || 1) });
}

function draftConfidenceSelectOptions(selectedValue) {
  const selectedLevel = draftConfidenceLevel(selectedValue, "exact");
  return [
    "exact",
    "very_sure",
    "sure",
    "medium",
    "unsure",
  ].map((level) => (
    `<option value="${esc(level)}"${level === selectedLevel ? " selected" : ""}>${esc(draftCompactConfidenceLabel(level))}</option>`
  )).join("");
}

function draftWordTokens(text = "") {
  const source = String(text || "");
  const tokens = [];
  const matcher = /\S+/gu;
  let match = matcher.exec(source);
  while (match) {
    const tokenText = String(match[0] || "");
    tokens.push({
      index: tokens.length,
      text: tokenText,
      start: match.index,
      end: match.index + tokenText.length,
    });
    match = matcher.exec(source);
  }
  return tokens;
}

function draftConfidenceForWord(segments = [], word = {}, fallback = 100) {
  const start = Math.max(0, Number(word?.start || 0));
  const end = Math.max(start, Number(word?.end || start));
  if (end <= start) return draftClampConfidence(fallback, 100);
  let best = null;
  let bestOverlap = 0;
  for (const segment of Array.isArray(segments) ? segments : []) {
    const segmentStart = Math.max(0, Number(segment?.start || 0));
    const segmentEnd = Math.max(segmentStart, Number(segment?.end || segmentStart));
    const overlap = Math.min(end, segmentEnd) - Math.max(start, segmentStart);
    if (overlap <= 0) continue;
    if (segmentStart <= start && segmentEnd >= end) {
      return draftClampConfidence(segment?.confidence, fallback);
    }
    if (overlap > bestOverlap) {
      best = segment;
      bestOverlap = overlap;
    }
  }
  return best ? draftClampConfidence(best?.confidence, fallback) : draftClampConfidence(fallback, 100);
}

function draftResolveActiveVariant(line = {}, options = {}) {
  const variants = Array.isArray(line?.variants) ? line.variants : [];
  if (!variants.length) return null;
  const preferredActiveId = String(options?.preferredActiveId ?? line?.active_variant_id ?? "").trim();
  if (preferredActiveId) {
    const byId = variants.find((item) => String(item?.id || "").trim() === preferredActiveId);
    if (byId) return byId;
  }
  let bestScore = Number.NEGATIVE_INFINITY;
  for (const item of variants) {
    bestScore = Math.max(bestScore, Number(draftClampConfidence(item?.confidence, 100)));
  }
  const leaders = variants.filter((item) => Number(draftClampConfidence(item?.confidence, 100)) === bestScore);
  if (leaders.length <= 1) return leaders[0] || variants[0] || null;
  const fallbackText = String(options?.fallbackText || "");
  if (fallbackText) {
    const byText = leaders.find((item) => String(item?.text || "") === fallbackText);
    if (byText) return byText;
  }
  const byActiveFlag = leaders.find((item) => item?.is_active);
  if (byActiveFlag) return byActiveFlag;
  return leaders[0] || variants[0] || null;
}

function draftLineHasConfidenceTie(line = {}) {
  const variants = Array.isArray(line?.variants) ? line.variants : [];
  if (variants.length < 2) return false;
  let bestScore = Number.NEGATIVE_INFINITY;
  for (const item of variants) {
    bestScore = Math.max(bestScore, Number(draftClampConfidence(item?.confidence, 100)));
  }
  let leaders = 0;
  for (const item of variants) {
    if (Number(draftClampConfidence(item?.confidence, 100)) === bestScore) leaders += 1;
    if (leaders > 1) return true;
  }
  return false;
}

function draftNewVariantTextFromInput(inputNode = null, line = null) {
  const typedText = String(inputNode?.value || "").trim();
  if (typedText) return typedText;
  return String(draftActiveVariant(line || {})?.text || "").trim();
}

function draftApplyResolvedActiveVariant(line = {}, options = {}) {
  const variants = Array.isArray(line?.variants) ? line.variants : [];
  if (!variants.length) {
    if (line && typeof line === "object") line.active_variant_id = "";
    return null;
  }
  const active = draftResolveActiveVariant(line, options);
  const activeId = String(active?.id || variants[0]?.id || "").trim();
  variants.forEach((item) => {
    item.is_active = String(item?.id || "").trim() === activeId;
  });
  if (line && typeof line === "object") line.active_variant_id = activeId;
  return active || variants[0] || null;
}

function draftWordConfidenceEditorUI(lineId = "", variantId = "", text = "", segments = []) {
  const safeLineId = String(lineId || "");
  const safeVariantId = String(variantId || "");
  const words = draftWordTokens(text);
  if (!words.length) {
    return `<div class="draft-word-confidence-empty muted small">${esc(draftUiText("wordConfidenceEmpty"))}</div>`;
  }
  return `
    <div class="draft-word-confidence-editor" data-line-id="${esc(safeLineId)}" data-variant-id="${esc(safeVariantId)}">
      <div class="draft-word-confidence-header">
        <div class="draft-variants-list-title">${esc(draftUiText("wordConfidenceTitle"))}</div>
        <div class="muted small">${esc(draftUiText("wordConfidenceHint"))}</div>
      </div>
      <div class="draft-word-confidence-flow">
        ${words.map((word) => {
          const confidence = draftConfidenceForWord(segments, word, 100);
          const selectedValue = confidence < 100 ? confidence : "exact";
          return `
            <label class="draft-word-confidence-item" title="${esc(word.text)}">
              <span class="draft-word-confidence-token">${esc(word.text)}</span>
              <span class="draft-word-confidence-select-wrap">
                <select
                  class="select draft-word-confidence-select"
                  data-line-id="${esc(safeLineId)}"
                  data-variant-id="${esc(safeVariantId)}"
                  data-word-start="${word.start}"
                  data-word-end="${word.end}"
                  aria-label="${esc(`${draftUiText("wordConfidenceTitle")}: ${word.text}`)}"
                >
                  ${draftConfidenceSelectOptions(selectedValue)}
                </select>
              </span>
            </label>
          `;
        }).join("")}
      </div>
    </div>
  `;
}

function teardownSongConfidenceMenus() {
  if (typeof songConfidenceMenusCleanup === "function") {
    songConfidenceMenusCleanup();
  }
  songConfidenceMenusCleanup = null;
}

function resetSongConfidenceMenuPanel(menu) {
  if (!(menu instanceof HTMLDetailsElement)) return;
  const panel = menu.querySelector(".song-line-variants-panel");
  if (!(panel instanceof HTMLElement)) return;
  panel.classList.remove("is-visible");
  panel.style.left = "";
  panel.style.right = "";
}

function syncSongConfidenceMenuTrigger(menu) {
  if (!(menu instanceof HTMLDetailsElement)) return;
  const anchor = menu.closest(".song-confidence-word-anchor");
  if (!(anchor instanceof HTMLElement)) return;
  const trigger = anchor.querySelector(".song-confidence-word-trigger");
  if (!(trigger instanceof HTMLElement)) return;
  trigger.setAttribute("aria-expanded", menu.open ? "true" : "false");
}

function positionSongConfidenceMenu(menu) {
  if (!(menu instanceof HTMLDetailsElement)) return;
  if (!menu.open) return;
  const panel = menu.querySelector(".song-line-variants-panel");
  const anchor = menu.closest(".song-confidence-word-anchor");
  if (!(panel instanceof HTMLElement) || !(anchor instanceof HTMLElement)) return;
  panel.style.left = "";
  panel.style.right = "";
  const visualViewport = window.visualViewport || null;
  const viewportOffsetLeft = Number(visualViewport?.offsetLeft || 0);
  const viewportWidth = Number(
    visualViewport?.width ||
    window.innerWidth ||
    document.documentElement?.clientWidth ||
    0,
  );
  if (viewportWidth <= 0) return;
  const gutter = 16;
  const minLeft = viewportOffsetLeft + gutter;
  const maxRight = viewportOffsetLeft + viewportWidth - gutter;
  const panelRect = panel.getBoundingClientRect();
  let offsetLeft = 0;
  if (panelRect.right > maxRight) {
    offsetLeft -= panelRect.right - maxRight;
  }
  if (panelRect.left + offsetLeft < minLeft) {
    offsetLeft += minLeft - (panelRect.left + offsetLeft);
  }
  panel.style.left = `${Math.round(offsetLeft)}px`;
  window.requestAnimationFrame(() => {
    if (!menu.open) return;
    panel.classList.add("is-visible");
  });
}

function setupSongConfidenceMenus(root) {
  teardownSongConfidenceMenus();
  if (!(root instanceof HTMLElement)) return;
  const menus = Array.from(root.querySelectorAll(".song-confidence-word-menu"))
    .filter((node) => node instanceof HTMLDetailsElement);
  if (!menus.length) return;

  const closeMenus = (exceptMenu = null) => {
    menus.forEach((menu) => {
      if (!(menu instanceof HTMLDetailsElement)) return;
      if (menu === exceptMenu) return;
      if (!menu.open) return;
      menu.open = false;
      resetSongConfidenceMenuPanel(menu);
      syncSongConfidenceMenuTrigger(menu);
    });
  };

  const schedulePosition = (menu) => {
    if (!(menu instanceof HTMLDetailsElement) || !menu.open) return;
    window.requestAnimationFrame(() => positionSongConfidenceMenu(menu));
  };

  const toggleEntries = menus.map((menu) => {
    const onToggle = () => {
      syncSongConfidenceMenuTrigger(menu);
      if (!menu.open) {
        resetSongConfidenceMenuPanel(menu);
        return;
      }
      closeMenus(menu);
      schedulePosition(menu);
    };
    menu.addEventListener("toggle", onToggle);
    syncSongConfidenceMenuTrigger(menu);
    if (menu.open) schedulePosition(menu);
    return { menu, onToggle };
  });

  const onRootPointerDown = (event) => {
    const target = event.target;
    if (!(target instanceof HTMLElement)) return;
    if (!target.closest(".song-confidence-word-trigger, .song-confidence-word-toggle, .song-confidence-word")) return;
    if (target.closest(".song-line-variants-panel")) return;
    event.stopPropagation();
  };

  const onRootClick = (event) => {
    const target = event.target;
    if (!(target instanceof HTMLElement)) return;
    const trigger = target.closest(".song-confidence-word-trigger, .song-confidence-word-toggle, .song-confidence-word");
    if (!(trigger instanceof HTMLElement) || !root.contains(trigger)) return;
    if (target.closest(".song-line-variants-panel")) return;
    const anchor = trigger.closest(".song-confidence-word-anchor");
    if (!(anchor instanceof HTMLElement)) return;
    const menu = anchor.querySelector(".song-confidence-word-menu");
    if (!(menu instanceof HTMLDetailsElement)) return;
    const triggerNode = anchor.querySelector(".song-confidence-word-trigger");
    event.preventDefault();
    event.stopPropagation();
    if (menu.open) {
      menu.open = false;
      resetSongConfidenceMenuPanel(menu);
      syncSongConfidenceMenuTrigger(menu);
      if (triggerNode instanceof HTMLElement) triggerNode.focus({ preventScroll: true });
      return;
    }
    closeMenus(menu);
    menu.open = true;
    syncSongConfidenceMenuTrigger(menu);
    schedulePosition(menu);
    if (triggerNode instanceof HTMLElement) triggerNode.focus({ preventScroll: true });
  };

  const onRootKeyDown = (event) => {
    const target = event.target;
    if (!(target instanceof HTMLElement)) return;
    const trigger = target.closest(".song-confidence-word-trigger");
    if (!(trigger instanceof HTMLElement) || !root.contains(trigger)) return;
    const key = String(event?.key || "");
    if (key !== "Enter" && key !== " ") return;
    event.preventDefault();
    trigger.click();
  };

  const onDocumentClick = (event) => {
    const target = event.target;
    if (!(target instanceof HTMLElement)) return;
    if (root.contains(target) && target.closest(".song-confidence-word-anchor")) return;
    closeMenus();
  };

  const onDocumentKeyDown = (event) => {
    if (String(event?.key || "") !== "Escape") return;
    closeMenus();
  };

  const onResize = () => {
    menus.forEach((menu) => {
      if (menu instanceof HTMLDetailsElement && menu.open) {
        positionSongConfidenceMenu(menu);
      }
    });
  };

  root.addEventListener("pointerdown", onRootPointerDown, { capture: true });
  root.addEventListener("click", onRootClick, true);
  root.addEventListener("keydown", onRootKeyDown);
  document.addEventListener("click", onDocumentClick, true);
  document.addEventListener("keydown", onDocumentKeyDown);
  window.addEventListener("resize", onResize, { passive: true });
  window.addEventListener("scroll", onResize, true);
  window.addEventListener("orientationchange", onResize, { passive: true });
  window.visualViewport?.addEventListener("resize", onResize, { passive: true });

  songConfidenceMenusCleanup = () => {
    root.removeEventListener("pointerdown", onRootPointerDown, { capture: true });
    root.removeEventListener("click", onRootClick, true);
    root.removeEventListener("keydown", onRootKeyDown);
    document.removeEventListener("click", onDocumentClick, true);
    document.removeEventListener("keydown", onDocumentKeyDown);
    window.removeEventListener("resize", onResize);
    window.removeEventListener("scroll", onResize, true);
    window.removeEventListener("orientationchange", onResize);
    window.visualViewport?.removeEventListener("resize", onResize);
    toggleEntries.forEach(({ menu, onToggle }) => {
      menu.removeEventListener("toggle", onToggle);
      resetSongConfidenceMenuPanel(menu);
      syncSongConfidenceMenuTrigger(menu);
    });
  };
}

function draftIsPopoverEditingField(node = document.activeElement) {
  if (!(node instanceof HTMLInputElement || node instanceof HTMLTextAreaElement || node instanceof HTMLSelectElement)) {
    return false;
  }
  return node.classList.contains("draft-variant-text-input")
    || node.classList.contains("draft-new-variant-text")
    || node.classList.contains("draft-variant-confidence-select")
    || node.classList.contains("draft-variant-confidence-level")
    || node.classList.contains("draft-variant-confidence-input")
    || node.classList.contains("draft-word-confidence-select")
    || node.classList.contains("draft-word-confidence-input")
    || node.classList.contains("draft-segment-selection-text");
}

function draftNormalizeSegments(segments, text = "") {
  return normalizeConfidenceSegments(Array.isArray(segments) ? segments : [], {
    maxLength: String(text || "").length,
    dropExact: true,
  });
}

function draftSegmentSnippet(text, segment = {}) {
  const source = String(text || "");
  const start = Math.max(0, Number(segment?.start || 0));
  const end = Math.max(start, Number(segment?.end || start));
  const snippet = source.slice(start, end).trim();
  return snippet || source.slice(start, end) || "";
}

function draftReplaceSegmentsInRange(segments, nextSegment, text = "") {
  const sourceText = String(text || "");
  const normalized = draftNormalizeSegments(segments, sourceText);
  const start = Math.max(0, Number(nextSegment?.start || 0));
  const end = Math.max(start, Number(nextSegment?.end || start));
  if (end <= start) return normalized;
  const confidence = draftConfidenceFromInput(
    nextSegment?.confidence ?? nextSegment?.level ?? nextSegment?.confidence_level,
    100,
  );
  const next = [];
  for (const item of normalized) {
    if (item.end <= start || item.start >= end) {
      next.push(item);
      continue;
    }
    if (item.start < start) {
      next.push({ ...item, end: start });
    }
    if (item.end > end) {
      next.push({ ...item, start: end });
    }
  }
  if (confidence < 100) {
    const confidenceLevel = draftConfidenceLevel(confidence, "sure");
    next.push({
      start,
      end,
      level: confidenceLevel,
      confidence_level: confidenceLevel,
      confidence,
    });
  }
  return draftNormalizeSegments(next, sourceText);
}

function draftActiveVariant(line = {}) {
  return draftResolveActiveVariant(line);
}

function splitLyricsLines(input) {
  return String(input || "")
    .replace(/\r\n?/g, "\n")
    .split("\n");
}

const LYRICS_VARIANT_HEADING_RE = /^(?:вариант|version|variant|versioon|versija|версія)\s*(?:[ivxlcdm]+|\d+)\s*[:.)-]*$/iu;
const LYRICS_SECTION_HEADING_RE = /^(?:куплет|припев|приспів|приспев|chorus|verse|bridge|intro|outro|рефрен|refrain|refrään)\s*(?:[ivxlcdm]+|\d+)?\s*[:.)-]*$/iu;
const LYRICS_ARCHIVE_REF_RE = /(?:^|[\s(])(?:№\s*\d+|[ФF]\.\s*[-\w]+|Оп\.\s*\d+|Д\.\s*\d+|Л\.\s*[\d-]+)(?:$|[\s).,;:])/iu;
const LYRICS_DATE_RE = /\b(?:\d{1,2}[./]\d{1,2}[./]\d{2,4}|\d{1,2}\s+(?:январ[ьяе]?|феврал[ьяе]?|март[а]?|апрел[ьяе]?|ма[йяе]?|июн[ьяе]?|июл[ьяе]?|август[ае]?|сентябр[ьяе]?|октябр[ьяе]?|ноябр[ьяе]?|декабр[ьяе]?))\b/iu;
const LYRICS_DOC_KEYWORD_RE = /\b(?:письмо|правлени[ея]|войсков(?:ого|ому|ое)|атаман(?:у|а)?|канцелярия|архив|машинопись|подлинник|доклад|протокол|телеграмма|рапорт|получено|генерал(?:-| )?лейтенант|есаул|адъютант)\b/iu;
const LYRICS_LOCATION_REF_RE = /^(?:г\.|город|ст\.|станица|село|деревня)\s*[А-ЯЁA-Z][\p{L}\p{M} .-]*$/u;

function decodeLyricsHtmlEntities(value = "") {
  const input = String(value || "");
  if (!input || !/[&]/.test(input)) return input;
  return decodeHtmlEntitiesStrict(input);
}

function normalizeLyricsDisplayLine(value = "") {
  return decodeLyricsHtmlEntities(String(value || ""))
    .replace(/\u00A0/g, " ")
    .replace(/[\u200B-\u200D\uFEFF]/g, "")
    .replace(/[ \t]+/g, " ")
    .trim();
}

function stripTrailingLyricsFootnoteMarker(value = "") {
  const line = String(value || "").trim();
  if (!line) return "";
  return line
    .replace(/^(.{6,}[\p{L}\p{M}][^]*?[\p{L}\p{M}\])»"'!?….:,;-])\s*(?:\(?\s*(?:\d{1,2}|[IVXLC]{1,5})\s*\)?)$/u, "$1")
    .replace(/^(.{10,}[\p{L}\p{M}][^]*?[\p{L}\p{M}])\s+\[(?:\d{1,2}|[IVXLC]{1,5})\]$/u, "$1")
    .trim();
}

function draftComparableLineText(value = "") {
  return stripTrailingLyricsFootnoteMarker(normalizeLyricsDisplayLine(value || ""))
    .replace(/\s+/g, " ")
    .trim()
    .toLowerCase();
}

function draftLineLooksForeignToSource(variants = [], sourceText = "", activeText = "") {
  const sourceComparable = draftComparableLineText(sourceText);
  if (!sourceComparable) return false;
  const activeComparable = draftComparableLineText(activeText);
  if (activeComparable && activeComparable === sourceComparable) return false;
  return !(Array.isArray(variants) ? variants : []).some((variant) => (
    draftComparableLineText(variant?.text || "") === sourceComparable
  ));
}

function draftDeduplicateVariantsByText(variants = [], preferredActiveId = "") {
  const out = [];
  const seen = new Map();
  const activeId = String(preferredActiveId || "").trim();
  for (const variant of Array.isArray(variants) ? variants : []) {
    const comparable = draftComparableLineText(variant?.text || "");
    const key = comparable || `__empty__${out.length}`;
    const variantType = String(variant?.variant_type || "").trim();
    const isEditableVariant = variantType === "manual" || variantType === "suggested";
    const existingIndex = seen.get(key);
    if (existingIndex === undefined) {
      out.push(variant);
      seen.set(key, out.length - 1);
      continue;
    }
    const existing = out[existingIndex];
    const existingType = String(existing?.variant_type || "").trim();
    const existingIsEditableVariant = existingType === "manual" || existingType === "suggested";
    if (isEditableVariant && existingIsEditableVariant) {
      out.push(variant);
      continue;
    }
    const nextId = String(variant?.id || "").trim();
    const prevId = String(existing?.id || "").trim();
    const nextIsActive = !!variant?.is_active || (activeId && nextId === activeId);
    const prevIsActive = !!existing?.is_active || (activeId && prevId === activeId);
    const nextIsManual = variantType === "manual";
    const prevIsManual = existingType === "manual";
    if ((nextIsActive && !prevIsActive) || (nextIsManual && !prevIsManual)) {
      out[existingIndex] = variant;
    }
  }
  return out;
}

function countRegexMatches(value = "", pattern) {
  const matches = String(value || "").match(pattern);
  return Array.isArray(matches) ? matches.length : 0;
}

function isUppercaseHeavyLine(value = "") {
  const text = String(value || "");
  const upper = countRegexMatches(text, /\p{Lu}/gu);
  const lower = countRegexMatches(text, /\p{Ll}/gu);
  return upper >= 12 && upper > (lower * 2.4);
}

function buildLyricsDisplayContext(rawLines = []) {
  const firstMeaningful = (Array.isArray(rawLines) ? rawLines : [])
    .map((line) => stripTrailingLyricsFootnoteMarker(normalizeLyricsDisplayLine(line)))
    .filter(Boolean)
    .slice(0, 6);
  let score = 0;
  firstMeaningful.forEach((line) => {
    if (LYRICS_ARCHIVE_REF_RE.test(line)) score += 2;
    if (LYRICS_DOC_KEYWORD_RE.test(line)) score += 1;
    if (LYRICS_DATE_RE.test(line)) score += 1;
    if (isUppercaseHeavyLine(line)) score += 1;
  });
  return {
    documentLike: score >= 4,
  };
}

function isLikelyDocumentNoiseLine(value = "", context = {}) {
  const line = stripTrailingLyricsFootnoteMarker(normalizeLyricsDisplayLine(value));
  if (!line) return true;
  if (LYRICS_VARIANT_HEADING_RE.test(line)) return true;
  if (LYRICS_SECTION_HEADING_RE.test(line)) return true;
  if (/^(?:\d+|[IVXLC]{1,6})$/iu.test(line)) return true;
  if (LYRICS_ARCHIVE_REF_RE.test(line)) return true;

  const digitCount = countRegexMatches(line, /\d/g);
  const hasDate = LYRICS_DATE_RE.test(line) || (digitCount >= 5 && /\b(?:18|19|20)\s?\d{2}\b/.test(line));
  const hasDocKeyword = LYRICS_DOC_KEYWORD_RE.test(line);
  const uppercaseHeavy = isUppercaseHeavyLine(line);

  if (context?.documentLike) {
    if (hasDocKeyword) return true;
    if (hasDate && digitCount >= 3) return true;
    if (LYRICS_LOCATION_REF_RE.test(line)) return true;
    if (uppercaseHeavy) return true;
  }

  if (hasDate && (uppercaseHeavy || hasDocKeyword || digitCount >= 6)) return true;
  if (/^№\s*\d+$/iu.test(line)) return true;
  return false;
}

function createLyricsDisplayEntries(rawLyrics, options = {}) {
  const rawLines = Array.isArray(rawLyrics) ? rawLyrics : splitLyricsLines(rawLyrics);
  const context = buildLyricsDisplayContext(rawLines);
  const keepBlankLines = options?.keepBlankLines === true;
  const entries = rawLines.map((raw, index) => {
    const normalized = stripTrailingLyricsFootnoteMarker(normalizeLyricsDisplayLine(raw));
    if (!normalized) return { raw: String(raw || ""), text: "", index, hidden: false };
    return {
      raw: String(raw || ""),
      text: normalized,
      index,
      hidden: isLikelyDocumentNoiseLine(normalized, context),
    };
  });
  return {
    context,
    entries: entries.filter((entry) => {
      if (!entry.text) return keepBlankLines;
      return entry.hidden !== true;
    }),
  };
}

function draftNormalizeVariantState(rawVariant = {}, options = {}) {
  const fallbackText = String(options?.fallbackText || "");
  const text = String(rawVariant?.text ?? fallbackText);
  const confidence = draftClampConfidence(
    rawVariant?.confidence_level ?? rawVariant?.level ?? rawVariant?.confidence,
    options?.fallbackConfidence ?? 100,
  );
  const requestedVariantType = String(rawVariant?.variant_type || options?.defaultVariantType || "").trim().toLowerCase();
  const variantType = requestedVariantType === "manual" || requestedVariantType === "suggested" || requestedVariantType === "imported"
    ? requestedVariantType
    : "manual";
  return {
    id: String(rawVariant?.id || options?.fallbackId || `variant_${Date.now()}`),
    text,
    confidence,
    confidence_level: draftConfidenceLevel(confidence),
    confidence_segments: draftNormalizeSegments(
      rawVariant?.confidence_segments ?? rawVariant?.segments ?? [],
      text,
    ),
    variant_type: variantType,
    is_active: rawVariant?.is_active === true || Number(rawVariant?.is_active || 0) === 1,
  };
}

function draftEnsureLineState(line = {}, sourceText = "", index = 0, options = {}) {
  const safeText = String(sourceText || "");
  const lineIdPrefix = String(options?.lineIdPrefix || "line");
  const variantIdPrefix = String(options?.variantIdPrefix || "variant");
  const baseLine = line && typeof line === "object" ? { ...line } : {};
  const rawVariants = Array.isArray(baseLine?.variants) ? baseLine.variants : [];
  let variants = rawVariants.map((item, variantIndex) => draftNormalizeVariantState(item, {
    fallbackText: safeText,
    fallbackId: `${variantIdPrefix}_${index + 1}_${variantIndex + 1}`,
    defaultVariantType: "imported",
  }));
  variants = draftDeduplicateVariantsByText(variants, baseLine?.active_variant_id);
  let active = draftResolveActiveVariant({ variants, active_variant_id: baseLine?.active_variant_id }, {
    preferredActiveId: baseLine?.active_variant_id,
    fallbackText: safeText,
  }) || variants.find((item) => String(item?.text || "") === safeText) || variants[0] || null;

  if (!options?.preserveForeignVariants && draftLineLooksForeignToSource(variants, safeText, active?.text || "")) {
    variants = [];
    active = null;
  }

  if (!variants.length) {
    active = draftNormalizeVariantState({}, {
      fallbackText: safeText,
      fallbackId: `${variantIdPrefix}_${index + 1}_1`,
      fallbackConfidence: 100,
    });
    variants.push(active);
  }

  if (safeText !== String(active?.text || "")) {
    const bySameText = variants.find((item) => String(item?.text || "") === safeText);
    if (bySameText) {
      active = bySameText;
    } else {
      const injected = draftNormalizeVariantState({
        id: `${variantIdPrefix}_${index + 1}_active`,
        text: safeText,
        confidence: active?.confidence ?? 100,
        variant_type: active?.variant_type || "manual",
        is_active: false,
        confidence_segments: [],
      }, {
        fallbackText: safeText,
        fallbackId: `${variantIdPrefix}_${index + 1}_active`,
        fallbackConfidence: active?.confidence ?? 100,
      });
      variants.unshift(injected);
      active = injected;
    }
  }

  variants.forEach((item) => {
    item.confidence = draftClampConfidence(item?.confidence, 100);
    item.confidence_level = draftConfidenceLevel(item?.confidence);
    item.confidence_segments = draftNormalizeSegments(item?.confidence_segments, item?.text || "");
  });
  active = draftApplyResolvedActiveVariant({ ...baseLine, variants }, {
    preferredActiveId: baseLine?.active_variant_id,
    fallbackText: safeText,
  }) || active;
  const activeId = String(active?.id || variants[0]?.id || "");

  return {
    id: String(baseLine?.id || `${lineIdPrefix}_${index + 1}`),
    line_key: String(baseLine?.line_key || `line_${index + 1}`),
    sort_order: index,
    active_variant_id: activeId,
    variants,
  };
}

function draftBuildLinesFromLyricsMeta(lyricsText = "", lyricsMetaInput = null, options = {}) {
  const sourceLines = splitLyricsLines(lyricsText);
  const payload = parseLyricsMetaPayload(lyricsMetaInput);
  const metaLines = Array.isArray(payload?.lines) ? payload.lines : [];
  return sourceLines.map((sourceText, index) => draftEnsureLineState(metaLines[index], sourceText, index, options));
}

function draftResyncLines(lines = [], lyricsText = "", options = {}) {
  const sourceLines = splitLyricsLines(lyricsText);
  const baseLines = Array.isArray(lines) ? lines : [];
  return sourceLines.map((sourceText, index) => draftEnsureLineState(baseLines[index], sourceText, index, {
    ...options,
    preserveForeignVariants: true,
  }));
}

function draftSyncEditableLines(lines = [], lyricsText = "", options = {}) {
  const sourceLines = splitLyricsLines(lyricsText);
  const baseLines = Array.isArray(lines) ? lines : [];
  return sourceLines.map((sourceText, index) => {
    const seedLine = draftEnsureLineState(baseLines[index], String(draftActiveVariant(baseLines[index] || {})?.text || sourceText || ""), index, {
      ...options,
      preserveForeignVariants: true,
    });
    const nextLine = {
      ...seedLine,
      variants: (Array.isArray(seedLine?.variants) ? seedLine.variants : []).map((variant) => ({ ...variant })),
    };
    const active = draftActiveVariant(nextLine || {});
    if (active && String(active.text || "") !== String(sourceText || "")) {
      active.text = String(sourceText || "");
      active.confidence_segments = [];
    }
    return draftEnsureLineState(nextLine, sourceText, index, {
      ...options,
      preserveForeignVariants: true,
    });
  });
}

function draftBuildLyricsMeta(lines = [], lyricsText = "") {
  const normalizedLines = draftResyncLines(lines, lyricsText);
  return {
    lines: normalizedLines.map((line, index) => {
      const activeVariantId = String(draftActiveVariant(line || {})?.id || line?.active_variant_id || "").trim();
      const variants = (Array.isArray(line?.variants) ? line.variants : []).map((variant, variantIndex) => {
        const normalized = draftNormalizeVariantState(variant, {
          fallbackText: String(variant?.text || ""),
          fallbackId: `serialized_variant_${index + 1}_${variantIndex + 1}`,
          fallbackConfidence: variant?.confidence ?? 100,
        });
        const level = draftConfidenceLevel(normalized.confidence);
        return {
          id: normalized.id,
          text: normalized.text,
          confidence: normalized.confidence,
          confidence_level: level,
          confidence_segments: draftNormalizeSegments(normalized.confidence_segments, normalized.text),
          variant_type: normalized.variant_type,
          is_active: String(normalized.id || "") === activeVariantId,
        };
      });
      return {
        id: String(line?.id || `line_${index + 1}`),
        line_key: String(line?.line_key || `line_${index + 1}`),
        active_variant_id: activeVariantId || String(variants[0]?.id || ""),
        variants,
      };
    }),
  };
}

function draftAttachLinesState(rootNode, lines = []) {
  if (!(rootNode instanceof HTMLElement)) return;
  rootNode.__lyricsConfidenceLines = lines;
}

function draftReadAttachedLinesState(rootNode) {
  if (!(rootNode instanceof HTMLElement)) return [];
  return Array.isArray(rootNode.__lyricsConfidenceLines) ? rootNode.__lyricsConfidenceLines : [];
}

function draftEditorLyricsMeta(rootNode, lyricsText = "") {
  const existingLines = draftReadAttachedLinesState(rootNode);
  if (existingLines.length) {
    return draftBuildLyricsMeta(existingLines, lyricsText);
  }
  const initialMeta = rootNode && typeof rootNode === "object" ? (rootNode.__lyricsConfidenceMeta || null) : null;
  const seededLines = draftBuildLinesFromLyricsMeta(lyricsText, initialMeta, {
    lineIdPrefix: "editor_line",
    variantIdPrefix: "editor_variant",
    preserveForeignVariants: true,
  });
  return draftBuildLyricsMeta(seededLines, lyricsText);
}

function draftLinesToLyrics(lines = []) {
  const composed = [...(Array.isArray(lines) ? lines : [])]
    .sort((a, b) => Number(a?.sort_order || 0) - Number(b?.sort_order || 0))
    .map((line) => String(draftActiveVariant(line)?.text || "").replace(/\r\n?/g, "\n").replace(/^\n+|\n+$/g, ""))
    .join("\n");
  return composed
    .replace(/^(?:[ \t]*\n)+/g, "")
    .replace(/(?:\n[ \t]*)+$/g, "");
}

function draftOpStoreFor(draftId) {
  const key = String(draftId || "");
  if (!draftOpStatusStore.has(key)) {
    draftOpStatusStore.set(key, new Map());
  }
  return draftOpStatusStore.get(key);
}

function draftOpStatusLabel(status = "") {
  const normalized = String(status || "").trim().toLowerCase();
  if (normalized === "pending") return draftUiText("opStatusPending");
  if (normalized === "applied") return draftUiText("opStatusApplied");
  if (normalized === "persisted") return draftUiText("opStatusPersisted");
  return normalized || draftUiText("opStatusPending");
}

function draftLineRowsUI(lines = []) {
  const safeLines = Array.isArray(lines) ? lines : [];
  return safeLines.map((line, index) => {
    const active = draftActiveVariant(line);
    const activeText = String(active?.text || "");
    const activeConfidence = Number(active?.confidence || 100);
    const variants = Array.isArray(line?.variants) ? line.variants : [];
    return `
      <div class="songCard draft-line ${draftConfidenceBand(activeConfidence)}" data-line-id="${esc(line.id)}" style="${draftConfidenceStyleValue(activeConfidence)}">
        <div class="draft-line-header">
          <div class="draft-line-meta">
            <span class="badge">${index + 1}</span>
          </div>
          <button class="btn ghost draft-variants-toggle" type="button" data-line-id="${esc(line.id)}" aria-label="${esc(draftUiText("variantsToggle"))}" title="${esc(draftUiText("variantsToggle"))}">&#9776;</button>
        </div>
        <textarea class="textarea draft-line-input" data-line-id="${esc(line.id)}" data-confidence="${Math.max(0, Math.min(100, Math.round(activeConfidence)))}">${esc(activeText)}</textarea>
        <div class="actions draft-line-ai-actions">
          <button class="btn ghost draft-ai-copy" type="button" data-line-id="${esc(line.id)}">${esc(draftUiText("aiCopy"))}</button>
        </div>
        <div class="draft-variants-panel hidden" id="draft_variants_${esc(line.id)}">
          ${variants.map((variant) => `
            <div class="draft-variant-row ${variant?.is_active ? "is-active" : ""}">
              <div class="draft-variant-text">${esc(String(variant?.text || ""))}</div>
              <div class="draft-variant-controls">
                <span class="badge">${esc(draftVariantTypeLabel(variant?.variant_type || "manual"))}</span>
              </div>
            </div>
          `).join("")}
          <div class="draft-add-variant">
            <input class="input draft-new-variant-text" type="text" placeholder="${esc(draftUiText("newVariantPlaceholder"))}" data-line-id="${esc(line.id)}" />
            <div class="draft-add-variant-actions">
              <button class="btn ghost draft-add-variant-btn" type="button" data-line-id="${esc(line.id)}" data-line-index="${index}">${esc(draftUiText("addVariantManual"))}</button>
            </div>
          </div>
        </div>
      </div>
    `;
  }).join("");
}

function draftLineActionsPanelUI(line = null, index = -1) {
  if (!line) {
    const emptyText = uiLocale() === "ru"
      ? "Выберите строку кнопкой ≡ рядом с текстом."
      : uiLocale() === "uk"
        ? "Оберіть рядок кнопкою ≡ поруч із текстом."
        : uiLocale() === "et"
          ? "Vali rida nupuga ≡ teksti kõrval."
          : "Pick a line using the ≡ button next to the text.";
    return `<div class="muted small">${esc(emptyText)}</div>`;
  }
  const active = draftActiveVariant(line);
  const activeText = String(active?.text || "");
  const activeConfidence = Number(active?.confidence || 100);
  const variants = Array.isArray(line?.variants) ? line.variants : [];
  const safeIndex = Math.max(0, Number(index || 0));
  return `
    <div class="songCard draft-line-actions ${draftConfidenceBand(activeConfidence)}" data-line-id="${esc(line.id)}" style="${draftConfidenceStyleValue(activeConfidence)}">
      <div class="draft-line-header">
        <div class="draft-line-meta">
          <span class="badge">${safeIndex + 1}</span>
        </div>
      </div>
      <div class="draft-line-current" style="${draftConfidenceStyleValue(activeConfidence)}">${esc(activeText || " ")}</div>
      <div class="actions draft-line-ai-actions">
        <button class="btn ghost draft-ai-copy" type="button" data-line-id="${esc(line.id)}">${esc(draftUiText("aiCopy"))}</button>
      </div>
      <div class="draft-variants-panel">
        ${variants.map((variant) => `
          <div class="draft-variant-row ${variant?.is_active ? "is-active" : ""}">
            <div class="draft-variant-text">${esc(String(variant?.text || ""))}</div>
            <div class="draft-variant-controls">
              <span class="badge">${esc(draftVariantTypeLabel(variant?.variant_type || "manual"))}</span>
            </div>
          </div>
        `).join("")}
        <div class="draft-add-variant">
          <input class="input draft-new-variant-text" type="text" placeholder="${esc(draftUiText("newVariantPlaceholder"))}" data-line-id="${esc(line.id)}" />
          <div class="draft-add-variant-actions">
            <button class="btn ghost draft-add-variant-btn" type="button" data-line-id="${esc(line.id)}" data-line-index="${safeIndex}">${esc(draftUiText("addVariantManual"))}</button>
          </div>
        </div>
      </div>
    </div>
  `;
}

function draftLinePopoverUI(line = null, index = -1, options = {}) {
  if (!line) return "";
  const normalizedLine = draftEnsureLineState(line, String(draftActiveVariant(line)?.text || ""), Math.max(0, Number(index || 0)), {
    lineIdPrefix: String(line?.id || "line"),
    variantIdPrefix: `popover_variant_${Math.max(0, Number(index || 0)) + 1}`,
  });
  const active = draftActiveVariant(normalizedLine);
  const activeConfidence = draftClampConfidence(active?.confidence, 100);
  const activeComparable = draftComparableLineText(active?.text || "");
  const variants = [...(Array.isArray(normalizedLine?.variants) ? normalizedLine.variants : [])].filter((variant) => {
    const variantId = String(variant?.id || "").trim();
    const isActive = variantId && variantId === String(active?.id || "").trim();
    if (isActive) return true;
    return draftComparableLineText(variant?.text || "") !== activeComparable;
  });
  const activeVariantId = String(active?.id || variants[0]?.id || "");
  const canRemoveVariant = variants.length > 1;
  const safeIndex = Math.max(0, Number(index || 0));
  const pendingNewVariantText = String(options?.newVariantText || "");

  return `
    <div class="ac-line-popover-card ${draftConfidenceBand(activeConfidence)}" data-line-id="${esc(normalizedLine.id)}" style="${draftConfidenceStyleValue(activeConfidence)}">
      <div class="draft-line-header">
        <div class="draft-line-meta">
          <span class="draft-line-meta-label">${esc(draftLineNumberLabel(safeIndex + 1))}</span>
        </div>
      </div>
      <div class="draft-variants-list-title">${esc(draftUiText("variantsList"))}</div>
      <div class="draft-variants-panel">
        ${variants.map((variant, variantIndex) => {
          const variantId = String(variant?.id || "");
          const isActive = variantId && variantId === activeVariantId;
          const variantText = String(variant?.text || "");
          const variantConfidence = draftClampConfidence(variant?.confidence, isActive ? activeConfidence : 80);
          const canActivateManually = !isActive;
          const wordEditorMarkup = draftWordConfidenceEditorUI(
            normalizedLine.id,
            variantId,
            variantText,
            draftNormalizeSegments(variant?.confidence_segments, variantText),
          );
          return `
          <div class="draft-variant-row ${draftConfidenceBand(variantConfidence)} ${isActive ? "is-active" : ""}" style="${draftConfidenceStyleValue(variantConfidence)}">
            <div class="draft-variant-main">
              <div class="draft-variant-head">
                <div class="draft-variant-title-row">
                  <span class="draft-variant-index">${esc(draftVariantNumberLabel(variantIndex + 1))}</span>
                  ${isActive ? `<span class="badge draft-variant-state">${esc(draftUiText("activeVariant"))}</span>` : ""}
                </div>
                <div class="draft-variant-top-actions">
                  <button class="btn ghost draft-variant-remove" type="button" data-line-id="${esc(normalizedLine.id)}" data-variant-id="${esc(variantId)}" ${canRemoveVariant ? "" : "disabled"} aria-label="${esc(draftUiText("removeVariantTitle"))}" title="${esc(draftUiText("removeVariantTitle"))}"><span aria-hidden="true">&times;</span></button>
                </div>
              </div>
              ${canActivateManually ? `<div class="draft-variant-utility-row"><button class="btn ghost draft-variant-activate" type="button" data-line-id="${esc(normalizedLine.id)}" data-variant-id="${esc(variantId)}" aria-label="${esc(draftUiText("useVariant"))}" title="${esc(draftUiText("useVariant"))}">${esc(draftUiText("useVariant"))}</button></div>` : ""}
              <div class="draft-variant-inline">
                <input class="input draft-variant-text-input" type="text" value="${esc(variantText)}" data-line-id="${esc(normalizedLine.id)}" data-variant-id="${esc(variantId)}" placeholder="${esc(draftUiText("newVariantPlaceholder"))}" />
              </div>
              ${wordEditorMarkup}
            </div>
          </div>
        `;
        }).join("")}
        <div class="draft-add-variant">
          <input class="input draft-new-variant-text" type="text" value="${esc(pendingNewVariantText)}" placeholder="${esc(draftUiText("newVariantPlaceholder"))}" data-line-id="${esc(normalizedLine.id)}" />
          <div class="draft-add-variant-actions">
            <button class="btn ghost draft-add-variant-btn" type="button" data-line-id="${esc(normalizedLine.id)}" data-line-index="${safeIndex}">${esc(draftUiText("addLineVariant"))}</button>
          </div>
        </div>
      </div>
    </div>
  `;
}

