function normalizeSectionToken(line) {
  return String(line || "")
    .toLowerCase()
    .replace(/[.:!?,;()[\]{}"'\-–—]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function isSectionToken(line, keywords) {
  const token = normalizeSectionToken(line);
  if (!token) return false;
  const normalized = token.replace(/\s+\d+$/, "").trim();
  return keywords.includes(normalized);
}

function repeatCountFromText(text = "") {
  const source = String(text || "").toLowerCase();
  if (/(?:\(|\s|^)(?:x|×)\s*2(?:\)|\s|$)/i.test(source)) return 2;
  if (/(?:\(|\s|^)2\s*(?:раза|рази|раз|times|x|korda)(?:\)|\s|$)/i.test(source)) return 2;
  if (/(?:\(|\s|^)(?:два\s+раза|двічі|twice|bis)(?:\)|\s|$)/i.test(source)) return 2;
  if (/(?:\(|\s|^)(?:repeat(?:s|ed)?|повтор(?:ить|яется|ится)?|повторити|повторюється|повториться|kordub|korrata)(?:\s*2|\s+twice|\s+два\s+раза|\s+2\s*(?:раза|рази|раз|times|korda))?(?:\)|\s|$)/i.test(source)) return 2;
  return 0;
}

function sectionTokenInfo(line, keywords) {
  const token = normalizeSectionToken(line);
  if (!token) return { match: false, repeatCount: 0 };
  const withoutRepeat = token
    .replace(/\b(?:x|×)\s*2\b/gi, " ")
    .replace(/\b2\s*(?:раза|рази|раз|times|x|korda)\b/gi, " ")
    .replace(/\b(?:два\s+раза|двічі|twice|bis)\b/gi, " ")
    .replace(/\b(?:repeat(?:s|ed)?|повтор(?:ить|яется|ится)?|повторити|повторюється|повториться|kordub|korrata)(?:\s*2|\s+twice|\s+два\s+раза|\s+2\s*(?:раза|рази|раз|times|korda))?\b/gi, " ")
    .replace(/\s+\d+$/, "")
    .replace(/\s+/g, " ")
    .trim();
  const normalized = withoutRepeat || token.replace(/\s+\d+$/, "").trim();
  return {
    match: keywords.includes(normalized),
    repeatCount: repeatCountFromText(line),
  };
}

function stanzaPlainLines(stanza = {}) {
  const source = Array.isArray(stanza?.lines) ? stanza.lines : [];
  return source.map((item) => ({ ...item }));
}

function stanzaPlainText(stanza = {}) {
  return stanzaPlainLines(stanza).map((item) => item.text).join("\n").trim();
}

function stanzaLineCount(stanza = {}) {
  return stanzaPlainLines(stanza).map((item) => String(item?.text || "").trim()).filter(Boolean).length;
}

function cleanRepeatNotationText(text = "") {
  return String(text || "")
    .replace(/\s*:,\s*:\s*/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function isPreviousLineRepeatInstruction(text = "") {
  const source = cleanRepeatNotationText(text).toLowerCase();
  if (!source) return false;
  const compact = source.replace(/[()[\]{}"'.:,;!?\-–—]+/g, " ").replace(/\s+/g, " ").trim();
  if (!compact) return false;
  return (
    /^(?:последн(?:яя|юю)|крайн(?:яя|юю))\s+(?:строк(?:а|у)|строчк(?:а|у)|рядок)\s+(?:повтор(?:яется|ится|ить|и(?:ть)?))(?:\s*(?:2|два)\s*раза?)?$/.test(compact)
    || /^(?:остання|останній)\s+(?:строк(?:а|у)|рядок)\s+(?:повторюється|повториться|повторити)(?:\s*(?:2|двічі|два)\s*рази?)?$/.test(compact)
    || /^(?:last|previous)\s+line\s+(?:repeat|repeats|repeated|twice)(?:\s*(?:2|twice|times))?$/.test(compact)
    || /^repeat\s+(?:the\s+)?(?:last|previous)\s+line(?:\s*(?:2|twice|times))?$/.test(compact)
    || /^viimane\s+rida\s+(?:kordub|korrata)(?:\s*2\s*korda)?$/.test(compact)
  );
}

function splitLinesIntoRepeatRuns(lines = []) {
  const runs = [];
  let activeType = "verse";
  let activeLines = [];
  const pushActive = () => {
    const safeLines = activeLines
      .map((item) => ({ ...item, text: String(item?.text || "").trim() }))
      .filter((item) => item.text);
    if (safeLines.length) runs.push({ type: activeType, lines: safeLines });
    activeLines = [];
  };
  const addLine = (type, sourceLine, text) => {
    const cleanText = cleanRepeatNotationText(text);
    if (!cleanText) return;
    if (activeType !== type) {
      pushActive();
      activeType = type;
    }
    activeLines.push({ ...sourceLine, text: cleanText });
  };
  const markPreviousLineRepeat = () => {
    let lastLine = null;
    if (activeLines.length) {
      lastLine = activeLines.pop();
      pushActive();
    } else {
      const lastRun = runs[runs.length - 1];
      if (lastRun?.lines?.length) {
        lastLine = lastRun.lines.pop();
        if (!lastRun.lines.length) runs.pop();
      }
    }
    if (!lastLine) return false;
    runs.push({ type: "repeat", lines: [{ ...lastLine }] });
    activeType = "verse";
    activeLines = [];
    return true;
  };

  for (const sourceLine of Array.isArray(lines) ? lines : []) {
    let rest = String(sourceLine?.text || "");
    if (isPreviousLineRepeatInstruction(rest)) {
      markPreviousLineRepeat();
      continue;
    }
    while (rest.includes(":,:")) {
      const markerIndex = rest.indexOf(":,:");
      addLine(activeType, sourceLine, rest.slice(0, markerIndex));
      pushActive();
      activeType = activeType === "repeat" ? "verse" : "repeat";
      rest = rest.slice(markerIndex + 3);
    }
    addLine(activeType, sourceLine, rest);
  }
  pushActive();
  return runs;
}

function appendRepeatAwareBlocks(blocks, lines, fallbackType = "verse", extra = {}) {
  const runs = splitLinesIntoRepeatRuns(lines);
  if (!runs.length) return false;
  for (const run of runs) {
    const safeLines = run.lines.map((item) => ({ ...item }));
    const text = safeLines.map((item) => item.text).join("\n").trim();
    if (!text) continue;
    const repeatCount = run.type === "repeat" ? 2 : Number(extra?.repeatCount || 0) || undefined;
    blocks.push({
      ...extra,
      type: fallbackType,
      text,
      lines: safeLines,
      repeatCount,
    });
  }
  return true;
}

function detectAutoChorusIndexes(stanzas = []) {
  const mapped = Array.isArray(stanzas) ? stanzas : [];
  if (mapped.length < 2) return new Set();
  const candidates = mapped
    .map((stanza, index) => ({
      index,
      stanza,
      text: stanzaPlainText(stanza),
      lineCount: stanzaLineCount(stanza),
    }))
    .filter((item) => item.text && !item.stanza?.isChorus && !item.stanza?.isVerse && item.lineCount >= 3);
  if (candidates.length < 2) return new Set();

  let bestGroup = [];
  let bestAvgScore = 0;

  for (let i = 0; i < candidates.length; i += 1) {
    const left = candidates[i];
    const group = [left.index];
    const scores = [];
    for (let j = i + 1; j < candidates.length; j += 1) {
      const right = candidates[j];
      const similarity = compareStanzaSimilarity(left.text, right.text);
      const minLineCount = Math.min(left.lineCount, right.lineCount);
      const minTokenCount = Math.min(
        tokenizeCompareStanza(left.text).length,
        tokenizeCompareStanza(right.text).length,
      );
      const enoughOverlap = similarity.overlap >= Math.max(4, Math.floor(minTokenCount * 0.55));
      const strongEnough = similarity.score >= 0.84 || (similarity.score >= 0.76 && minLineCount >= 4 && enoughOverlap);
      if (!strongEnough) continue;
      group.push(right.index);
      scores.push(similarity.score);
    }
    if (group.length < 2) continue;
    const hasRealRepeatGap = group.some((value, idx) => idx > 0 && (value - group[idx - 1]) > 1);
    if (!hasRealRepeatGap) continue;
    const avgScore = scores.length ? (scores.reduce((sum, value) => sum + value, 0) / scores.length) : 1;
    if (group.length > bestGroup.length || (group.length === bestGroup.length && avgScore > bestAvgScore)) {
      bestGroup = group;
      bestAvgScore = avgScore;
    }
  }

  return new Set(bestGroup);
}

function parseStructuredLyrics(rawLyrics) {
  const entries = createLyricsDisplayEntries(rawLyrics, { keepBlankLines: true }).entries
    .map((entry) => ({
      raw: String(entry?.raw || ""),
      text: String(entry?.text || "").trim(),
      index: Number(entry?.index || 0),
    }));
  const hasAnyText = entries.some((entry) => entry.text);
  if (!hasAnyText) return { blocks: [], expanded: "" };

  const stanzas = [];
  let current = [];
  for (const entry of entries) {
    if (!entry.text) {
      if (current.length) {
        stanzas.push(current);
        current = [];
      }
      continue;
    }
    current.push(entry);
  }
  if (current.length) stanzas.push(current);

  const mappedStanzas = stanzas.map((lines, index) => {
    const first = lines[0]?.text || "";
    const tailEntries = lines.slice(1);
    const chorusInfo = sectionTokenInfo(first, CHORUS_KEYWORDS);
    const verseInfo = sectionTokenInfo(first, VERSE_KEYWORDS);
    return {
      index,
      lines,
      first,
      tailEntries,
      tail: tailEntries.map((item) => item.text).join("\n").trim(),
      isChorus: chorusInfo.match,
      isVerse: verseInfo.match,
      repeatCount: chorusInfo.repeatCount || verseInfo.repeatCount || repeatCountFromText(first),
    };
  });
  const autoChorusIndexes = detectAutoChorusIndexes(mappedStanzas);

  const blocks = [];
  let rememberedChorusText = "";
  let rememberedChorusLines = [];

  for (const stanza of mappedStanzas) {
    const { lines, tailEntries, tail, isChorus, isVerse } = stanza;
    const stanzaRepeatCount = Number(stanza.repeatCount || 0) || undefined;
    const isAutoChorus = autoChorusIndexes.has(stanza.index);
    if (isChorus) {
      if (tailEntries.length && tail) {
        rememberedChorusText = tail;
        rememberedChorusLines = tailEntries.map((item) => ({ ...item }));
        appendRepeatAwareBlocks(blocks, rememberedChorusLines, "chorus", { source: "full", repeatCount: stanzaRepeatCount });
      } else if (rememberedChorusLines.length && rememberedChorusText) {
        blocks.push({
          type: "chorus",
          text: rememberedChorusText,
          lines: rememberedChorusLines.map((item) => ({ ...item })),
          source: "ref",
          repeatCount: stanzaRepeatCount,
        });
      } else {
        const plainLines = lines.map((item) => ({ ...item }));
        appendRepeatAwareBlocks(blocks, plainLines, "verse", { source: "full", repeatCount: stanzaRepeatCount });
      }
      continue;
    }

    if (isAutoChorus) {
      const chorusLines = stanzaPlainLines(stanza);
      const chorusText = stanzaPlainText(stanza);
      if (chorusText) {
        rememberedChorusText = chorusText;
        rememberedChorusLines = chorusLines.map((item) => ({ ...item }));
        blocks.push({ type: "chorus", text: chorusText, lines: chorusLines, source: "full", inferred: true });
      }
      continue;
    }

    if (isVerse) {
      const verseLines = (tailEntries.length ? tailEntries : lines).map((item) => ({ ...item }));
      appendRepeatAwareBlocks(blocks, verseLines, "verse", { source: "full", repeatCount: stanzaRepeatCount });
      continue;
    }

    const plainLines = lines.map((item) => ({ ...item }));
    appendRepeatAwareBlocks(blocks, plainLines, "verse", { source: "full" });
  }

  const expanded = blocks.map((block) => {
    if (block.type === "chorus" && Number(block.repeatCount || 0) > 1) {
      return `${chorusMarkerLabel()}\n${block.text}\n${repeatMarkerLabel()}`.trim();
    }
    if (block.type === "chorus") return `${chorusMarkerLabel()}\n${block.text}`.trim();
    if (Number(block.repeatCount || 0) > 1) return `${block.text}\n${repeatMarkerLabel()}`.trim();
    return block.text;
  }).filter(Boolean).join("\n\n");

  return { blocks, expanded };
}

function parseLyricsMetaPayload(input) {
  if (!input) return null;
  if (typeof input === "string") {
    try {
      const parsed = JSON.parse(input);
      return parsed && typeof parsed === "object" ? parsed : null;
    } catch {
      return null;
    }
  }
  if (typeof input === "object") return input;
  return null;
}

function extractLyricsRenderLines(rawLyrics, lyricsMetaInput) {
  const displayEntries = createLyricsDisplayEntries(rawLyrics, { keepBlankLines: false }).entries;
  const normalizedLines = draftBuildLinesFromLyricsMeta(rawLyrics, lyricsMetaInput, {
    lineIdPrefix: "view_line",
    variantIdPrefix: "view_variant",
  });
  return displayEntries.map((entry, visibleIndex) => {
    const rawIndex = Number(entry?.index || 0);
    const line = normalizedLines[rawIndex] || null;
    const active = draftActiveVariant(line || {});
    const activeText = stripTrailingLyricsFootnoteMarker(normalizeLyricsDisplayLine(String(active?.text || entry?.raw || "")));
    if (!activeText) return null;
    const confidence = active ? draftClampConfidence(active.confidence, 100) : null;
    const variants = Array.isArray(line?.variants)
      ? line.variants.map((variant, variantIndex) => {
        const variantText = stripTrailingLyricsFootnoteMarker(normalizeLyricsDisplayLine(String(variant?.text || "")));
        if (!variantText) return null;
        const variantConfidence = draftClampConfidence(
          variant?.confidence,
          String(variant?.id || "") === String(draftActiveVariant(line || {})?.id || "") ? (confidence ?? 100) : 80,
        );
        return {
          id: String(variant?.id || `view_variant_${index + 1}_${variantIndex + 1}`),
          text: variantText,
          confidence: variantConfidence,
          confidence_level: draftConfidenceLevel(variantConfidence),
          confidence_segments: draftNormalizeSegments(variant?.confidence_segments, variantText),
          variant_type: String(variant?.variant_type || "manual"),
          is_active: String(variant?.id || "") === String(draftActiveVariant(line || {})?.id || ""),
        };
      })
      .filter(Boolean)
      : [];
    return {
      raw_index: rawIndex,
      line_id: String(line?.id || `view_line_${visibleIndex + 1}`),
      text: activeText,
      confidence,
      confidence_level: confidence === null ? null : draftConfidenceLevel(confidence),
      confidence_segments: draftNormalizeSegments(active?.confidence_segments, activeText),
      variants,
    };
  }).filter(Boolean);
}

function songConfidenceWordStyleValue(confidence) {
  const safeConfidence = draftClampConfidence(confidence, 100);
  const level = draftConfidenceLevel(safeConfidence);
  let red = 92;
  let green = 214;
  let blue = 132;
  let fillAlpha = 0.16;
  let borderAlpha = 0.3;
  if (level === "unsure") {
    red = 255;
    green = 146;
    blue = 78;
    fillAlpha = 0.2;
    borderAlpha = 0.38;
  } else if (level === "medium") {
    red = 255;
    green = 216;
    blue = 72;
    fillAlpha = 0.2;
    borderAlpha = 0.36;
  } else if (level === "sure") {
    red = 188;
    green = 222;
    blue = 84;
    fillAlpha = 0.18;
    borderAlpha = 0.34;
  } else if (level === "very_sure") {
    red = 96;
    green = 218;
    blue = 138;
    fillAlpha = 0.17;
    borderAlpha = 0.32;
  }
  return [
    `--song-confidence-r:${red}`,
    `--song-confidence-g:${green}`,
    `--song-confidence-b:${blue}`,
    `--song-confidence-fill-alpha:${fillAlpha.toFixed(3)}`,
    `--song-confidence-border-alpha:${borderAlpha.toFixed(3)}`,
  ].join(";");
}

function songLineAccentConfidence(segments = []) {
  const normalized = Array.isArray(segments) ? segments : [];
  if (!normalized.length) return 100;
  let lowest = 100;
  for (const segment of normalized) {
    lowest = Math.min(lowest, draftClampConfidence(segment?.confidence, 100));
  }
  return draftClampConfidence(lowest, 100);
}

function draftDisplayConfidenceSegments(text = "", segments = []) {
  const source = String(text || "");
  return draftNormalizeSegments(segments, source);
}

function renderTextWithConfidenceWords(text, segments = [], options = {}) {
  const source = String(text || "");
  const normalizedSegments = draftNormalizeSegments(segments, source);
  if (!normalizedSegments.length) return renderTextWithUnknownMarkers(source);
  const words = draftWordTokens(source);
  if (!words.length) return renderTextWithUnknownMarkers(source);
  const variantPanelMarkup = options?.variantPanelMarkup;
  const variantToggleTitle = String(options?.variantToggleTitle || "").trim();
  let out = "";
  let cursor = 0;
  for (const word of words) {
    const start = Math.max(cursor, Number(word?.start || 0));
    const end = Math.max(start, Number(word?.end || start));
    if (start > cursor) out += renderTextWithUnknownMarkers(source.slice(cursor, start));
    const wordText = source.slice(start, end);
    const confidence = draftConfidenceForWord(normalizedSegments, word, 100);
    if (confidence >= 100) {
      out += renderTextWithUnknownMarkers(wordText);
    } else {
      const confidenceLabel = draftConfidencePercent(confidence, 100);
      const confidenceStyle = songConfidenceWordStyleValue(confidence);
      const wordVariantPanelMarkup = typeof variantPanelMarkup === "function"
        ? String(variantPanelMarkup(word, wordText, words) || "")
        : String(variantPanelMarkup || "");
      const confidenceLabelMarkup = `<span class="song-confidence-word-label" aria-hidden="true">${esc(confidenceLabel)}</span>`;
      const confidenceWordMarkup = `<span class="song-confidence-word" data-confidence-label="" style="${confidenceStyle}" title="${esc(confidenceLabel)}" aria-label="${esc(confidenceLabel)}">${renderTextWithUnknownMarkers(wordText)}</span>`;
      if (wordVariantPanelMarkup) {
        const triggerLabel = esc(variantToggleTitle || confidenceLabel);
        out += `<span class="song-confidence-word-anchor" style="${confidenceStyle}"><details class="song-confidence-word-menu"><summary class="song-confidence-word-toggle" aria-label="${triggerLabel}" title="${triggerLabel}"><span>${esc(confidenceLabel)}</span></summary>${wordVariantPanelMarkup}</details><span class="song-confidence-word-trigger" role="button" tabindex="0" aria-label="${triggerLabel}" title="${triggerLabel}" aria-expanded="false">${confidenceLabelMarkup}${confidenceWordMarkup}</span></span>`;
      } else {
        out += `<span class="song-confidence-word-anchor song-confidence-word-anchor-static" style="${confidenceStyle}" title="${esc(confidenceLabel)}" aria-label="${esc(confidenceLabel)}">${confidenceLabelMarkup}${confidenceWordMarkup}</span>`;
      }
    }
    cursor = end;
  }
  if (cursor < source.length) {
    out += renderTextWithUnknownMarkers(source.slice(cursor));
  }
  return out || renderTextWithUnknownMarkers(source);
}

function renderEditorTextWithConfidenceWords(text, segments = []) {
  const source = String(text || "");
  const normalizedSegments = draftNormalizeSegments(segments, source);
  if (!normalizedSegments.length) return escDisplayText(source);
  const words = draftWordTokens(source);
  if (!words.length) return escDisplayText(source);
  let out = "";
  let cursor = 0;
  for (const word of words) {
    const start = Math.max(cursor, Number(word?.start || 0));
    const end = Math.max(start, Number(word?.end || start));
    if (start > cursor) out += escDisplayText(source.slice(cursor, start));
    const wordText = source.slice(start, end);
    const confidence = draftConfidenceForWord(normalizedSegments, word, 100);
    if (confidence >= 100) {
      out += escDisplayText(wordText);
    } else {
      const confidenceStyle = songConfidenceWordStyleValue(confidence);
      out += `<span class="editor-confidence-word" style="${confidenceStyle}">${escDisplayText(wordText)}</span>`;
    }
    cursor = end;
  }
  if (cursor < source.length) out += escDisplayText(source.slice(cursor));
  return out || escDisplayText(source);
}

function renderLyricsEditorOverlayLines(sourceLines = [], lines = []) {
  const safeSourceLines = Array.isArray(sourceLines) ? sourceLines : [];
  const safeLines = Array.isArray(lines) ? lines : [];
  return safeSourceLines.map((sourceText, index) => {
    const line = safeLines[index] || null;
    const active = draftActiveVariant(line || {});
    const content = String(sourceText ?? active?.text ?? "");
    const segments = draftDisplayConfidenceSegments(content, active?.confidence_segments);
    const markup = renderEditorTextWithConfidenceWords(content, segments);
    return `<div class="ac-lyrics-overlay-line">${markup || "&nbsp;"}</div>`;
  }).join("");
}

function renderLyricsEditorMeasureLines(sourceLines = []) {
  const safeSourceLines = Array.isArray(sourceLines) ? sourceLines : [];
  return safeSourceLines.map((sourceText) => {
    const content = String(sourceText ?? "");
    return `<div class="ac-lyrics-measure-line"><span class="ac-lyrics-measure-anchor">${content ? escDisplayText(content) : "&nbsp;"}</span></div>`;
  }).join("");
}

function ensureLyricsEditorMeasureContent(editorNode) {
  if (!(editorNode instanceof HTMLElement)) return null;
  let measureNode = editorNode.querySelector(".ac-lyrics-measure");
  if (!(measureNode instanceof HTMLElement)) {
    measureNode = document.createElement("div");
    measureNode.className = "ac-lyrics-measure";
    measureNode.setAttribute("aria-hidden", "true");
    const contentNode = document.createElement("div");
    contentNode.className = "ac-lyrics-measure-content";
    measureNode.appendChild(contentNode);
    const overlayNode = editorNode.querySelector(".ac-lyrics-overlay");
    if (overlayNode instanceof HTMLElement) {
      overlayNode.insertAdjacentElement("afterend", measureNode);
    } else {
      editorNode.insertBefore(measureNode, editorNode.firstChild);
    }
  }
  const measureContentNode = measureNode.querySelector(".ac-lyrics-measure-content");
  return measureContentNode instanceof HTMLElement ? measureContentNode : null;
}

function syncLyricsEditorOverlay(editorNode, textareaNode, sourceLines = [], lines = [], options = {}) {
  if (!(editorNode instanceof HTMLElement) || !(textareaNode instanceof HTMLTextAreaElement)) return;
  const overlayNode = editorNode.querySelector(".ac-lyrics-overlay");
  const overlayContentNode = overlayNode?.querySelector(".ac-lyrics-overlay-content");
  const measureContentNode = ensureLyricsEditorMeasureContent(editorNode);
  if (!(overlayNode instanceof HTMLElement) || !(overlayContentNode instanceof HTMLElement) || !(measureContentNode instanceof HTMLElement)) return;
  const textareaStyle = window.getComputedStyle(textareaNode);
  const textWhiteSpace = String(textareaStyle.whiteSpace || "").trim() || "pre";
  const textOverflowWrap = String(textareaStyle.overflowWrap || "").trim() || "normal";
  const textWordBreak = String(textareaStyle.wordBreak || "").trim() || "normal";
  const wrapsText = textWhiteSpace.includes("pre-wrap")
    || textWhiteSpace.includes("break-spaces")
    || textOverflowWrap !== "normal"
    || textWordBreak === "break-word"
    || textWordBreak === "break-all";
  overlayContentNode.innerHTML = renderLyricsEditorOverlayLines(sourceLines, lines);
  measureContentNode.innerHTML = renderLyricsEditorMeasureLines(sourceLines);
  const resolvedLineHeightPx = Number.isFinite(Number(options?.lineHeightPx))
    ? Number(options.lineHeightPx)
    : Number.parseFloat(String(textareaStyle.lineHeight || ""));
  const lineHeightPx = Math.max(18, Number.isFinite(resolvedLineHeightPx) ? resolvedLineHeightPx : 24);
  editorNode.style.setProperty("--ac-editor-text-pad-top", textareaStyle.paddingTop || "0px");
  editorNode.style.setProperty("--ac-editor-text-pad-right", textareaStyle.paddingRight || "0px");
  editorNode.style.setProperty("--ac-editor-text-pad-bottom", textareaStyle.paddingBottom || "0px");
  editorNode.style.setProperty("--ac-editor-text-pad-left", textareaStyle.paddingLeft || "0px");
  editorNode.style.setProperty("--ac-editor-font-family", textareaStyle.fontFamily || "inherit");
  editorNode.style.setProperty("--ac-editor-font-size", textareaStyle.fontSize || "16px");
  editorNode.style.setProperty("--ac-editor-font-weight", textareaStyle.fontWeight || "400");
  editorNode.style.setProperty("--ac-editor-font-style", textareaStyle.fontStyle || "normal");
  editorNode.style.setProperty("--ac-editor-letter-spacing", textareaStyle.letterSpacing || "normal");
  editorNode.style.setProperty("--ac-editor-line-height", `${lineHeightPx}px`);
  [overlayContentNode, measureContentNode].forEach((contentNode) => {
    contentNode.style.whiteSpace = textWhiteSpace;
    contentNode.style.overflowWrap = textOverflowWrap;
    contentNode.style.wordBreak = textWordBreak;
    contentNode.style.width = wrapsText ? "100%" : "max-content";
    contentNode.style.minWidth = "100%";
    contentNode.style.maxWidth = wrapsText ? "100%" : "none";
  });
  overlayNode.classList.toggle("has-confidence", Array.isArray(sourceLines) && sourceLines.some((sourceText, index) => {
    const line = Array.isArray(lines) ? lines[index] : null;
    const active = draftActiveVariant(line || {});
    return draftDisplayConfidenceSegments(
      String(sourceText ?? active?.text ?? ""),
      active?.confidence_segments,
    ).length > 0;
  }));
  syncLyricsEditorOverlayScroll(editorNode, textareaNode);
}

function syncLyricsEditorOverlayScroll(editorNode, textareaNode) {
  if (!(editorNode instanceof HTMLElement) || !(textareaNode instanceof HTMLTextAreaElement)) return;
  const overlayContentNode = editorNode.querySelector(".ac-lyrics-overlay-content");
  if (!(overlayContentNode instanceof HTMLElement)) return;
  const top = Math.max(0, Number(textareaNode.scrollTop || 0));
  const left = Math.max(0, Number(textareaNode.scrollLeft || 0));
  overlayContentNode.style.transform = `translate(${-Math.round(left)}px, ${-Math.round(top)}px)`;
}

function resolveLyricsEditorLineMetrics(editorNode, options = {}) {
  if (!(editorNode instanceof HTMLElement)) return [];
  const fallbackLineHeightPx = Math.max(18, Number(options?.fallbackLineHeightPx || 24));
  const fallbackPadTopPx = Math.max(0, Number(options?.fallbackPadTopPx || 0));
  const fallbackCount = Math.max(0, Number(options?.count || 0));
  const measureContentNode = editorNode.querySelector(".ac-lyrics-measure-content");
  const measureLines = measureContentNode instanceof HTMLElement
    ? Array.from(measureContentNode.querySelectorAll(".ac-lyrics-measure-line"))
    : [];
  if (!(measureContentNode instanceof HTMLElement) || !measureLines.length) {
    return Array.from({ length: fallbackCount }, (_, index) => ({
      top: fallbackPadTopPx + (index * fallbackLineHeightPx),
      height: fallbackLineHeightPx,
    }));
  }
  const contentRect = measureContentNode.getBoundingClientRect();
  const metrics = measureLines.map((lineNode, index) => {
    const anchorNode = lineNode instanceof HTMLElement
      ? lineNode.querySelector(".ac-lyrics-measure-anchor")
      : null;
    const lineTop = lineNode instanceof HTMLElement
      ? Math.max(0, Number(lineNode.offsetTop || 0))
      : fallbackPadTopPx + (index * fallbackLineHeightPx);
    let lineRects = [];
    if (anchorNode instanceof HTMLElement && typeof document?.createRange === "function") {
      const range = document.createRange();
      try {
        if (anchorNode.childNodes.length) range.selectNodeContents(anchorNode);
        else range.selectNode(anchorNode);
        lineRects = Array.from(range.getClientRects())
          .map((rect) => ({
            top: Math.max(0, Number(rect?.top || 0) - Number(contentRect.top || 0)),
            height: Math.max(1, Number(rect?.height || 0)),
          }))
          .filter((rect) => Number.isFinite(rect.top) && Number.isFinite(rect.height) && rect.height > 0.5);
      } catch {}
    }
    const firstRect = lineRects[0] || null;
    const top = firstRect
      ? firstRect.top
      : lineTop;
    const height = firstRect
      ? firstRect.height
      : fallbackLineHeightPx;
    return {
      top,
      height: Math.max(1, height),
    };
  });
  while (metrics.length < fallbackCount) {
    metrics.push({
      top: fallbackPadTopPx + (metrics.length * fallbackLineHeightPx),
      height: fallbackLineHeightPx,
    });
  }
  return metrics;
}

function collectSongWordVariants(meta = null, word = null) {
  const safeMeta = meta && typeof meta === "object" ? meta : null;
  const variants = Array.isArray(safeMeta?.variants) ? safeMeta.variants : [];
  const wordIndex = Number.isFinite(Number(word?.index)) ? Math.max(0, Number(word.index)) : -1;
  if (variants.length <= 1 || wordIndex < 0) return [];
  const activeVariantId = String(safeMeta?.active_variant_id || "").trim();
  const activeConfidence = draftClampConfidence(safeMeta?.confidence, 100);
  const seen = new Set();
  const entries = [];
  variants.forEach((variant, variantIndex) => {
    const variantText = String(variant?.text || "");
    const variantWords = draftWordTokens(variantText);
    const variantWord = variantWords[wordIndex];
    if (!variantWord) return;
    const variantId = String(variant?.id || `song_variant_${variantIndex + 1}`).trim();
    const isActive = !!variant?.is_active || (variantId && variantId === activeVariantId);
    const fallbackConfidence = draftClampConfidence(variant?.confidence, isActive ? activeConfidence : 100);
    const variantSegments = draftDisplayConfidenceSegments(variantText, variant?.confidence_segments);
    const confidence = draftConfidenceForWord(variantSegments, variantWord, fallbackConfidence);
    const text = String(variantWord.text || "").trim();
    if (!text) return;
    const key = `${text}\u0000${confidence}`;
    if (seen.has(key)) return;
    seen.add(key);
    entries.push({
      text,
      confidence,
    });
  });
  entries.sort((a, b) => {
    const confidenceDelta = Number(b?.confidence || 0) - Number(a?.confidence || 0);
    if (confidenceDelta !== 0) return confidenceDelta;
    return String(a?.text || "").localeCompare(String(b?.text || ""), uiLocale());
  });
  return entries;
}

function renderSongLyricVariantsPanel(meta = null, word = null) {
  const variants = collectSongWordVariants(meta, word);
  if (variants.length <= 1) return "";

  const variantsMarkup = variants.length
    ? variants.map((variant) => {
      const confidenceLabel = draftConfidencePercent(variant.confidence, 100);
      const confidenceStyle = songConfidenceWordStyleValue(variant.confidence);
      return `
      <li class="song-line-variant-row">
        <span class="song-line-variant-main">
          <span class="song-line-variant-text">${renderTextWithUnknownMarkers(variant.text)}</span>
          <span class="song-line-variant-confidence" style="${confidenceStyle}" aria-label="${esc(confidenceLabel)}" title="${esc(confidenceLabel)}">${esc(confidenceLabel)}</span>
        </span>
      </li>
    `;
    }).join("")
    : `<div class="muted small">${esc(draftUiText("confidenceSegmentsEmpty"))}</div>`;
  const totalCount = Math.max(0, variants.length);

  return `
    <div class="song-line-variants-panel">
      <div class="song-line-variants-copy">${esc(songVariantHypothesesText(totalCount))}</div>
      <ol class="song-line-variants-list">${variantsMarkup}</ol>
    </div>
  `;
}

function renderLyricLineWithConfidence(text, meta = null) {
  const safeMeta = meta && typeof meta === "object" ? meta : null;
  const content = String(text || "");
  const safeSegments = draftDisplayConfidenceSegments(content, safeMeta?.confidence_segments);
  const hasVariantMenu = Array.isArray(safeMeta?.variants) && safeMeta.variants.length > 1;
  const variantsCount = Math.max(0, Array.isArray(safeMeta?.variants) ? safeMeta.variants.length : 0);
  return content ? renderTextWithConfidenceWords(content, safeSegments, {
    variantPanelMarkup: hasVariantMenu ? ((word) => renderSongLyricVariantsPanel(safeMeta, word)) : "",
    variantToggleTitle: `${draftUiText("variantsList")}: ${variantsCount}`,
  }) : "&nbsp;";
}

function renderStructuredLyrics(rawLyrics, options = {}) {
  const renderWithUnknownMarks = (text) => renderTextWithUnknownMarkers(text);
  const parsed = parseStructuredLyrics(rawLyrics);
  const fallbackText = createLyricsDisplayEntries(rawLyrics, { keepBlankLines: true }).entries
    .map((entry) => entry.text)
    .join("\n")
    .trim();
  const renderLines = Array.isArray(options?.render_lines)
    ? options.render_lines
    : extractLyricsRenderLines(rawLyrics, options?.lyrics_meta || null);
  const lineMetaByIndex = new Map(renderLines.map((item) => [Number(item?.raw_index || 0), item]));
  const hasVisibleStructuredConfidence = renderLines.some((item) => {
    const segments = draftDisplayConfidenceSegments(item?.text || "", item?.confidence_segments);
    const variants = Array.isArray(item?.variants) ? item.variants : [];
    return segments.length > 0 || variants.length > 1;
  });
  const renderEntriesWithConfidence = (entries = []) => entries.map((entry) => (
    renderLyricLineWithConfidence(entry?.text || "", lineMetaByIndex.get(Number(entry?.index || 0)) || null)
  )).join("<br />");
  if (!parsed.blocks.length) {
    const fallbackEntries = createLyricsDisplayEntries(fallbackText, { keepBlankLines: false }).entries
      .map((entry) => ({ text: entry.text, index: entry.index }));
    return {
      html: fallbackText
        ? `<div class="song-lyric-block is-verse"><div class="song-lyric-prefix" aria-hidden="true"><span class="song-chorus-spacer"></span></div>${
          hasVisibleStructuredConfidence
            ? `<div class="lyrics song-primary-lyrics song-primary-lyrics-structured song-text song-lyric-text">${renderEntriesWithConfidence(fallbackEntries)}</div>`
            : `<pre class="lyrics song-primary-lyrics song-text song-lyric-text">${renderWithUnknownMarks(fallbackText)}</pre>`
        }</div>`
        : "",
      expanded: fallbackText,
    };
  }

  const html = parsed.blocks.map((block) => {
    const isChorus = block.type === "chorus";
    const isRepeat = Number(block.repeatCount || 0) > 1;
    const classes = [
      "song-lyric-block",
      isChorus ? "is-chorus" : "is-verse",
      isRepeat ? "is-repeat" : "",
      block.source === "ref" ? "is-chorus-ref" : "",
    ].filter(Boolean).join(" ");
    return `
      <div class="${classes}">
        <div class="song-lyric-prefix" aria-hidden="${isChorus ? "false" : "true"}">
          ${isChorus ? `<div class="song-chorus-label">${esc(`${chorusMarkerLabel()}:`)}</div>` : `<span class="song-chorus-spacer"></span>`}
        </div>
        ${isRepeat ? `<div class="song-repeat-label">${esc(repeatMarkerLabel())}</div>` : ``}
        ${
          hasVisibleStructuredConfidence
            ? `<div class="lyrics song-primary-lyrics song-primary-lyrics-structured song-text song-lyric-text">${renderEntriesWithConfidence(block.lines || [])}</div>`
            : `<pre class="lyrics song-primary-lyrics song-text song-lyric-text">${renderWithUnknownMarks(block.text)}</pre>`
        }
      </div>
    `;
  }).join("");

  return {
    html,
    expanded: parsed.expanded || fallbackText,
  };
}

function decodeLyricsProgressPercent(value) {
  const text = String(value || "");
  const allChars = (text.match(/\S/g) || []).length;
  if (!allChars) return 100;
  const unknownChars = countUnknownQuestionMarks(text);
  const safeKnown = Math.max(0, allChars - unknownChars);
  const pct = (safeKnown / allChars) * 100;
  return Math.max(0, Math.min(100, Math.round(pct * 10) / 10));
}

function isUnknownQuestionMarkAt(text, index) {
  if (text[index] !== "?") return false;
  const prev = index > 0 ? text[index - 1] : "";
  const next = index + 1 < text.length ? text[index + 1] : "";
  if (prev === "(" && next === ")") return true;
  return prev === "?" || next === "?";
}

function countUnknownQuestionMarks(text) {
  const src = String(text || "");
  let total = 0;
  for (let i = 0; i < src.length; i += 1) {
    if (isUnknownQuestionMarkAt(src, i)) total += 1;
  }
  return total;
}

function renderTextWithUnknownMarkers(text) {
  const src = String(text || "");
  let out = "";
  for (let i = 0; i < src.length; i += 1) {
    const ch = src[i];
    if (ch === "?" && isUnknownQuestionMarkAt(src, i)) {
      out += `<span class="song-unknown-char">?</span>`;
    } else {
      out += escDisplayText(ch);
    }
  }
  return out;
}

function normalizeCompareText(text = "") {
  return String(text || "").replace(/\r\n?/g, "\n").trim();
}

function compareSectionTokenKeywords() {
  return [...CHORUS_KEYWORDS, ...VERSE_KEYWORDS];
}

function splitCompareFallbackLines(lines = [], stanzaSize = 4) {
  const safeLines = Array.isArray(lines)
    ? lines.map((line) => String(line || "").trim()).filter(Boolean)
    : [];
  if (!safeLines.length) return [];
  if (safeLines.length <= stanzaSize) return [safeLines.join("\n")];
  const chunks = [];
  for (let index = 0; index < safeLines.length; index += stanzaSize) {
    const chunk = safeLines.slice(index, index + stanzaSize).join("\n").trim();
    if (chunk) chunks.push(chunk);
  }
  return chunks;
}

function splitLyricsToStanzasFallback(text = "") {
  const lines = splitLyricsLines(text)
    .map((line) => String(line || "").trim())
    .filter(Boolean);
  if (!lines.length) return [];
  if (lines.length <= 4) return [lines.join("\n")];
  const keywords = compareSectionTokenKeywords();
  const blocks = [];
  let current = [];
  const flushCurrent = () => {
    if (!current.length) return;
    blocks.push(...splitCompareFallbackLines(current, 4));
    current = [];
  };
  for (const line of lines) {
    if (isSectionToken(line, keywords)) {
      flushCurrent();
      current = [line];
      continue;
    }
    current.push(line);
  }
  flushCurrent();
  return blocks.length ? blocks : [lines.join("\n")];
}

function normalizeCompareBlock(rawBlock = "") {
  const lines = String(rawBlock || "")
    .replace(/\r\n?/g, "\n")
    .split("\n")
    .map((line) => String(line || "").trim());
  const nonEmptyLines = lines.filter(Boolean);
  if (!nonEmptyLines.length) return null;
  const firstLine = nonEmptyLines[0] || "";
  const isChorusBlock = isSectionToken(firstLine, CHORUS_KEYWORDS);
  const isVerseBlock = isSectionToken(firstLine, VERSE_KEYWORDS);
  const contentLines = (isChorusBlock || isVerseBlock) ? nonEmptyLines.slice(1) : nonEmptyLines;
  const content = contentLines.join("\n").trim();
  if (!content) return null;
  return {
    type: isChorusBlock ? "chorus" : "verse",
    text: content,
  };
}

function splitLyricsToStanzas(text = "") {
  const normalized = normalizeCompareText(text);
  if (!normalized) return [];
  const parsed = parseStructuredLyrics(normalized);
  if (Array.isArray(parsed?.blocks) && parsed.blocks.length) {
    return parsed.blocks
      .map((block) => ({
        type: block?.type === "chorus" ? "chorus" : "verse",
        text: String(block?.text || "").trim(),
      }))
      .filter((block) => block.text);
  }
  const stanzas = normalized
    .split(/\n\s*\n+/)
    .map((chunk) => normalizeCompareBlock(chunk))
    .filter(Boolean);
  if (stanzas.length > 1) return stanzas;
  return splitLyricsToStanzasFallback(normalized)
    .map((chunk) => normalizeCompareBlock(chunk))
    .filter(Boolean);
}

function normalizeCompareStanza(text = "") {
  return String(text || "")
    .replace(/\r\n?/g, "\n")
    .toLowerCase()
    .split("\n")
    .map((line) => line.trim())
    .filter(Boolean)
    .join("\n")
    .replace(/[^\p{L}\p{N}\n\s]+/gu, " ")
    .replace(/[ \t]+/g, " ")
    .replace(/\n{2,}/g, "\n")
    .trim();
}

function tokenizeCompareStanza(text = "") {
  const normalized = normalizeCompareStanza(text).replace(/\n/g, " ");
  return normalized.match(/[\p{L}\p{N}]+/gu) || [];
}

function compareStanzaSimilarity(sourceText = "", targetText = "") {
  const sourceNorm = normalizeCompareStanza(sourceText);
  const targetNorm = normalizeCompareStanza(targetText);
  if (!sourceNorm || !targetNorm) return { score: 0, overlap: 0 };
  if (sourceNorm === targetNorm) return { score: 1, overlap: 999 };

  const sourceTokens = tokenizeCompareStanza(sourceNorm);
  const targetTokens = tokenizeCompareStanza(targetNorm);
  if (!sourceTokens.length || !targetTokens.length) return { score: 0, overlap: 0 };

  const sourceFreq = new Map();
  sourceTokens.forEach((token) => sourceFreq.set(token, (sourceFreq.get(token) || 0) + 1));
  const targetFreq = new Map();
  targetTokens.forEach((token) => targetFreq.set(token, (targetFreq.get(token) || 0) + 1));

  let overlap = 0;
  sourceFreq.forEach((count, token) => {
    const rightCount = targetFreq.get(token) || 0;
    if (rightCount > 0) overlap += Math.min(count, rightCount);
  });
  if (!overlap) return { score: 0, overlap: 0 };

  const dice = (2 * overlap) / (sourceTokens.length + targetTokens.length);
  const sourceLines = sourceNorm.split("\n").filter(Boolean).length || 1;
  const targetLines = targetNorm.split("\n").filter(Boolean).length || 1;
  const lineBalance = Math.min(sourceLines, targetLines) / Math.max(sourceLines, targetLines);
  const score = (dice * 0.92) + (lineBalance * 0.08);
  return { score, overlap };
}

function alignCompareStanzas(sourceStanzas = [], targetStanzas = []) {
  const src = Array.isArray(sourceStanzas) ? sourceStanzas : [];
  const dst = Array.isArray(targetStanzas) ? targetStanzas : [];
  const rowCount = Math.max(src.length, dst.length);
  const rows = [];
  for (let idx = 0; idx < rowCount; idx += 1) {
    const hasSource = idx < src.length;
    const hasTarget = idx < dst.length;
    const sourceBlock = hasSource ? (src[idx] || null) : null;
    const targetBlock = hasTarget ? (dst[idx] || null) : null;
    const sourceText = hasSource ? String(sourceBlock?.text || "") : "";
    const targetText = hasTarget ? String(targetBlock?.text || "") : "";
    const isExact = hasSource
      && hasTarget
      && normalizeCompareStanza(sourceText) === normalizeCompareStanza(targetText);
    rows.push({
      sourceIndex: hasSource ? idx : null,
      targetIndex: hasTarget ? idx : null,
      sourceType: String(sourceBlock?.type || "verse"),
      targetType: String(targetBlock?.type || "verse"),
      isExact,
    });
  }
  return rows;
}

function diffWordsToKeepSet(sourceWords = [], targetWords = []) {
  const src = sourceWords.map((w) => String(w || "").toLowerCase());
  const dst = targetWords.map((w) => String(w || "").toLowerCase());
  const m = src.length;
  const n = dst.length;
  if (!m || !n) return new Set();
  const dp = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));
  for (let i = 1; i <= m; i += 1) {
    for (let j = 1; j <= n; j += 1) {
      if (src[i - 1] === dst[j - 1]) dp[i][j] = dp[i - 1][j - 1] + 1;
      else dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
    }
  }
  const keep = new Set();
  let i = m;
  let j = n;
  while (i > 0 && j > 0) {
    if (src[i - 1] === dst[j - 1]) {
      keep.add(i - 1);
      i -= 1;
      j -= 1;
      continue;
    }
    if (dp[i - 1][j] >= dp[i][j - 1]) i -= 1;
    else j -= 1;
  }
  return keep;
}

function compactCompareKeepSet(rawKeep = new Set(), sourceWords = []) {
  const sorted = [...rawKeep]
    .filter((idx) => Number.isInteger(idx) && idx >= 0)
    .sort((a, b) => a - b);
  if (!sorted.length) return new Set();
  const compact = new Set();
  let runStart = 0;
  while (runStart < sorted.length) {
    let runEnd = runStart;
    while (runEnd + 1 < sorted.length && sorted[runEnd + 1] === sorted[runEnd] + 1) {
      runEnd += 1;
    }
    const runLength = (runEnd - runStart) + 1;
    if (runLength >= 2) {
      for (let i = runStart; i <= runEnd; i += 1) compact.add(sorted[i]);
    } else {
      const idx = sorted[runStart];
      const token = String(sourceWords[idx] || "").toLowerCase().replace(/[^\p{L}\p{N}]+/gu, "");
      if (token.length >= 5) compact.add(idx);
    }
    runStart = runEnd + 1;
  }
  return compact;
}

function isCompareAttachedPunctuation(ch = "") {
  return /[.,!?;:)\]}\u00BB\u201D]/u.test(String(ch || ""));
}

function renderCompareWordMarkup(sourceText = "", targetText = "", options = {}) {
  const skipDiff = !!options.skipDiff;
  const src = String(sourceText || "");
  if (!src) return "";
  if (skipDiff) return renderTextWithUnknownMarkers(src);
  const dst = String(targetText || "");
  const matchWordRe = /[\p{L}\p{N}?]+/gu;
  const srcWords = src.match(matchWordRe) || [];
  const dstWords = dst.match(matchWordRe) || [];
  const keepRaw = diffWordsToKeepSet(srcWords, dstWords);
  const keep = compactCompareKeepSet(keepRaw, srcWords);
  let wordIndex = 0;
  let out = "";
  let lastIndex = 0;
  const renderWordRe = /[\p{L}\p{N}?]+/gu;
  let match = renderWordRe.exec(src);
  while (match) {
    const start = match.index;
    const end = start + match[0].length;
    out += renderTextWithUnknownMarkers(src.slice(lastIndex, start));
    let spanEnd = end;
    while (spanEnd < src.length && isCompareAttachedPunctuation(src[spanEnd])) spanEnd += 1;
    const idx = wordIndex;
    wordIndex += 1;
    const safeWord = renderTextWithUnknownMarkers(src.slice(start, spanEnd));
    if (keep.has(idx)) out += `<span class="song-version-word-diff">${safeWord}</span>`;
    else out += `<span class="song-version-word-similar">${safeWord}</span>`;
    lastIndex = spanEnd;
    match = renderWordRe.exec(src);
  }
  out += renderTextWithUnknownMarkers(src.slice(lastIndex));
  return out;
}

function decodingProgressText(percent) {
  const value = Number.isFinite(percent) ? percent : 100;
  const shown = Number.isInteger(value) ? String(value) : value.toFixed(1);
  if (uiLocale() === "ru") return `Песня расшифрована на ${shown}%`;
  if (uiLocale() === "uk") return `Пісню розшифровано на ${shown}%`;
  if (uiLocale() === "et") return `Laul on desifreeritud ${shown}%`;
  return `Song is deciphered by ${shown}%`;
}

function splitLyricsForEditor(rawLyrics) {
  const source = String(rawLyrics || "").replace(/\r\n?/g, "\n").trim();
  if (!source) return { lyrics: "", chorus: "", marker: chorusMarkerLabel() };
  const stanzas = source
    .split(/\n\s*\n+/g)
    .map((part) => part.split("\n").map((line) => line.trim()).filter(Boolean))
    .filter((lines) => lines.length > 0);
  const verseBlocks = [];
  let chorus = "";
  let marker = chorusMarkerLabel();
  let chorusTokenCount = 0;
  let chorusTextCount = 0;
  for (const lines of stanzas) {
    const first = String(lines[0] || "");
    if (isSectionToken(first, CHORUS_KEYWORDS)) {
      chorusTokenCount += 1;
      if (!marker || marker === chorusMarkerLabel()) marker = first || chorusMarkerLabel();
      const tail = lines.slice(1).join("\n").trim();
      if (tail) {
        chorusTextCount += 1;
        if (!chorus) chorus = tail;
      }
      continue;
    }
    verseBlocks.push(lines.join("\n").trim());
  }
  if (!chorus || chorusTokenCount !== 1 || chorusTextCount !== 1) {
    return { lyrics: source, chorus: "", marker: chorusMarkerLabel() };
  }
  return { lyrics: verseBlocks.filter(Boolean).join("\n\n").trim(), chorus, marker: marker || chorusMarkerLabel() };
}

function composeLyricsWithChorus(lyricsValue, chorusValue, chorusMarkerValue = "") {
  const lyricsRaw = String(lyricsValue || "").replace(/\r\n?/g, "\n");
  const chorusRaw = String(chorusValue || "").replace(/\r\n?/g, "\n");
  const hasLyrics = lyricsRaw.trim().length > 0;
  const hasChorus = chorusRaw.trim().length > 0;
  if (!hasChorus) return lyricsRaw;
  const lyrics = hasLyrics ? lyricsRaw.trimEnd() : "";
  const chorus = chorusRaw.trim();
  const marker = String(chorusMarkerValue || "").trim() || chorusMarkerLabel();
  if (!lyrics) return `${marker}\n${chorus}`.trim();
  return `${lyrics}\n\n${marker}\n${chorus}`.trim();
}

function syncDecodingIndicator(outputId, lyricsId, chorusId, markerId) {
  const node = qs(outputId);
  if (!node) return;
  const combined = composeLyricsWithChorus(
    qs(lyricsId)?.value || "",
    qs(chorusId)?.value || "",
    qs(markerId)?.value || ""
  );
  const percent = decodeLyricsProgressPercent(combined);
  const isComplete = Number.isFinite(percent) && percent >= 100;
  node.textContent = isComplete ? "" : decodingProgressText(percent);
  node.classList.toggle("hidden", isComplete);
}

