  const footerActionButtons = [editActionBtn, copyActionBtn, verifiedTranslationActionBtn, favActionBtn].filter(Boolean).join("");
  const hasHeaderSide = !!verifiedPill;
  const aiHubTitle = uiLocale() === "ru"
