    const availableCountriesByLang = buildLangCountryAvailabilityMap(ctx.langCountryCounts || []);
    const availablePeriodsByLangCountry = buildLangCountryPeriodAvailabilityMap(ctx.langCountryPeriodCounts || []);
    const lockedCountry = normalizeSongCountry(params.country || "") || "";
