        const slotLayoutStyle = `top:${inlineFormatCssPx(metric.top, padTopPx)};height:${inlineFormatCssPx(metric.height, lineHeightPx)};min-height:${inlineFormatCssPx(metric.height, lineHeightPx)};`;
        const buttonMarkup = hasText
